function getMonotonicNowMs() {
  return typeof globalThis.performance?.now === "function" ? globalThis.performance.now() : Date.now();
}

function normalizeTimingDurationMs(value) {
  const parsed = Number(value);
  if (!Number.isFinite(parsed) || parsed < 0) return 0;
  return Math.round(parsed * 10) / 10;
}

function recordRuntimeTimingSample(store, name, durationMs, details = {}) {
  const key = String(name || "").trim();
  if (!key) return null;

  const previous = store[key] || {};
  const count = Math.max(0, Math.trunc(Number(previous.count) || 0)) + 1;
  const lastMs = normalizeTimingDurationMs(durationMs);
  const previousAverage = Number(previous.avgMs);
  const avgMs = count === 1 || !Number.isFinite(previousAverage)
    ? lastMs
    : normalizeTimingDurationMs((previousAverage * (1 - RUNTIME_TIMING_EWMA_ALPHA)) + (lastMs * RUNTIME_TIMING_EWMA_ALPHA));
  const maxMs = normalizeTimingDurationMs(Math.max(Number(previous.maxMs) || 0, lastMs));

  store[key] = {
    ...details,
    count,
    lastMs,
    avgMs,
    maxMs,
    lastAt: Date.now(),
  };
  return store[key];
}

function serializeRuntimeTimingStore(store = {}) {
  return Object.fromEntries(
    Object.entries(store)
      .filter(([key]) => key)
      .map(([key, value]) => ([
        key,
        {
          ...value,
          count: Math.max(0, Math.trunc(Number(value?.count) || 0)),
          lastMs: normalizeTimingDurationMs(value?.lastMs),
          avgMs: normalizeTimingDurationMs(value?.avgMs),
          maxMs: normalizeTimingDurationMs(value?.maxMs),
          lastAt: Math.max(0, Math.trunc(Number(value?.lastAt) || 0)),
        },
      ])),
  );
}

function normalizeDecisionText(value, fallback = "") {
  const text = String(value ?? "").trim();
  return text || fallback;
}

function normalizeDecisionOwner(value) {
  const owner = normalizeDecisionText(value, "runtime");
  switch (owner) {
    case "looter":
      return "looting";
    case "banker":
      return "banking";
    case "routeBuilder":
      return "route";
    case "followTrain":
    case "partyFollow":
      return "followChain";
    default:
      return owner;
  }
}

function normalizeDecisionState(value, { acted = false } = {}) {
  const state = normalizeDecisionText(value).toLowerCase();
  if (["acted", "skipped", "blocked", "suppressed", "failed", "idle"].includes(state)) {
    return state;
  }
  return acted ? "acted" : "skipped";
}

function normalizeDecisionFamilies(value = []) {
  const list = Array.isArray(value) ? value : [value];
  return Array.from(new Set(
    list
      .map((entry) => normalizeDecisionText(entry))
      .filter(Boolean),
  ));
}

function summarizeDecisionAction(action = null) {
  if (!action || typeof action !== "object") {
    return null;
  }

  const type = normalizeDecisionText(action.type || action.kind || action.actionType, "action");
  const label = normalizeDecisionText(
    action.label
    || action.words
    || action.name
    || action.sustainKind
    || action.reason
    || action.walkReason,
  );

  return {
    type,
    label,
    moduleKey: normalizeDecisionText(action.moduleKey),
    ruleIndex: Number.isInteger(action.ruleIndex) ? action.ruleIndex : null,
  };
}

function summarizeDecisionResult(result = null) {
  if (!result || typeof result !== "object") {
    return null;
  }

  return {
    ok: result.ok == null ? null : result.ok === true,
    reason: normalizeDecisionText(result.reason || result.status || result.phase),
    action: normalizeDecisionText(result.action || result.kind),
  };
}

function formatDecisionReason(record = null) {
  const reason = normalizeDecisionText(record?.reason);
  if (reason) {
    return reason;
  }

  const resultReason = normalizeDecisionText(record?.result?.reason);
  if (resultReason) {
    return resultReason;
  }

  return record?.state === "acted" ? "acted" : "no action";
}

