function loadKnownMinibiaEntityNameKeys(fileName = "") {
  try {
    const documentPath = path.join(MINIBIA_DATA_ROOT, "current", fileName);
    const document = JSON.parse(fs.readFileSync(documentPath, "utf8"));
    return normalizeMonsterNames(document?.items?.map((entry) => entry?.name) || [])
      .map((name) => name.toLowerCase());
  } catch {
    return [];
  }
}

function expandMonsterNameKeysWithAlphaVariants(names = []) {
  const expanded = [];
  const seen = new Set();
  const append = (name) => {
    const key = String(name || "").trim().toLowerCase();
    if (!key || seen.has(key)) return;
    seen.add(key);
    expanded.push(key);
  };

  for (const name of normalizeMonsterNames(names)) {
    append(name);
    if (!/^alpha\s+/i.test(name)) {
      append(`Alpha ${name}`);
    }
  }

  return expanded;
}

function getAlphaBaseMonsterNameKey(name = "") {
  return String(name || "").trim().toLowerCase().replace(/^alpha\s+/i, "").trim();
}

const ALPHA_MONSTER_THREAT_BONUS = 1_000_000;

function getMinibiaMonsterThreatScore(monster = null) {
  const health = Math.max(0, Number(monster?.health) || 0);
  const experience = Math.max(0, Number(monster?.experience) || 0);
  const armor = Math.max(0, Number(monster?.armor) || 0);
  const speed = Math.max(0, Number(monster?.speed) || 0);
  const attackMax = (Array.isArray(monster?.attacks) ? monster.attacks : [])
    .reduce((max, attack) => Math.max(
      max,
      Math.abs(Number(attack?.max) || 0),
      Math.abs(Number(attack?.min) || 0),
    ), 0);

  return Math.round((experience * 1000) + (health * 12) + (armor * 80) + (speed * 3) + (attackMax * 20));
}

function loadKnownMinibiaMonsterThreatScores() {
  try {
    const documentPath = path.join(MINIBIA_DATA_ROOT, "current", "monsters.json");
    const document = JSON.parse(fs.readFileSync(documentPath, "utf8"));
    const scores = {};

    for (const monster of Array.isArray(document?.items) ? document.items : []) {
      const name = String(monster?.name || "").trim();
      if (!name) continue;

      const key = name.toLowerCase();
      const isAlpha = /^alpha\s+/i.test(name);
      const baseScore = getMinibiaMonsterThreatScore(monster);
      scores[key] = baseScore + (isAlpha ? ALPHA_MONSTER_THREAT_BONUS : 0);

      if (!isAlpha) {
        scores[`alpha ${key}`] = baseScore + ALPHA_MONSTER_THREAT_BONUS;
      }
    }

    return scores;
  } catch {
    return {};
  }
}

function getKnownMinibiaMonsterThreatScore(name = "") {
  const key = String(name || "").trim().toLowerCase();
  if (!key) return 0;

  const directScore = Number(KNOWN_MINIBIA_MONSTER_THREAT_SCORE_BY_NAME_KEY[key]);
  if (Number.isFinite(directScore)) {
    return directScore;
  }

  const baseKey = getAlphaBaseMonsterNameKey(key);
  if (baseKey && baseKey !== key) {
    const baseScore = Number(KNOWN_MINIBIA_MONSTER_THREAT_SCORE_BY_NAME_KEY[baseKey]);
    return (Number.isFinite(baseScore) ? baseScore : 0) + ALPHA_MONSTER_THREAT_BONUS;
  }

  return 0;
}

const KNOWN_MINIBIA_MONSTER_NAME_KEYS = Object.freeze(
  expandMonsterNameKeysWithAlphaVariants(loadKnownMinibiaEntityNameKeys("monsters.json")),
);
const KNOWN_MINIBIA_MONSTER_NAME_KEY_SET = new Set(KNOWN_MINIBIA_MONSTER_NAME_KEYS);
const KNOWN_MINIBIA_MONSTER_THREAT_SCORE_BY_NAME_KEY = Object.freeze(loadKnownMinibiaMonsterThreatScores());
