    const currentTarget = describeCurrentTarget(player.__target);
    const currentFollowTarget = describeCurrentTarget(player.__followTarget);
    const playerEntityId = readEntityId(player);
    const playerPendingPartyInviteId = Number.isFinite(Number(player?.__pendingPartyInvite))
