function buildCloseNonDefaultChatsExpression() {
  return `(() => {
    const game = window.gameClient;
    const channelManager = game?.interface?.channelManager;

    if (
      !channelManager
      || !Array.isArray(channelManager.channels)
      || typeof channelManager.closeChannel !== "function"
    ) {
      return { ok: false, reason: "channel manager unavailable" };
    }

    const getChannelName = (channel) => String(channel?.name || "").trim();
    const channels = Array.from(channelManager.channels || []);
    const defaultChannel = (
      (typeof channelManager.getChannelById === "function" && channelManager.getChannelById(0))
      || (typeof channelManager.getChannel === "function" && channelManager.getChannel("Default"))
      || channels.find((channel) => channel?.id === 0 || getChannelName(channel).toLowerCase() === "default")
      || null
    );
    const closableChannels = channels.filter((channel) => (
      channel
      && channel !== defaultChannel
      && channel?.id !== 0
      && getChannelName(channel).toLowerCase() !== "default"
    ));

    for (const channel of closableChannels) {
      try {
        channelManager.closeChannel(channel);
      } catch {}
    }

    if (defaultChannel && typeof channelManager.setActiveChannelElement === "function") {
      try {
        channelManager.setActiveChannelElement(defaultChannel);
      } catch {}
    }

    const activeChannel = typeof channelManager.getActiveChannel === "function"
      ? channelManager.getActiveChannel()
      : defaultChannel;

    return {
      ok: true,
      closedCount: closableChannels.length,
      closedChannelNames: closableChannels.map((channel) => getChannelName(channel)).filter(Boolean),
      remainingChannelNames: Array.from(channelManager.channels || []).map((channel) => getChannelName(channel)).filter(Boolean),
      activeChannelName: getChannelName(activeChannel),
    };
  })()`;
}

function buildDialogueStateExpression() {
  return `(() => {
    const game = window.gameClient;
    const channelManager = game?.interface?.channelManager;
    const dialogueManagers = [
      game?.interface?.dialogueManager,
      game?.interface?.npcManager,
      game?.interface?.modalManager,
      game?.interface?.chatNpc,
    ].filter(Boolean);
    const collectValues = (value) => {
      if (!value) return [];
      if (Array.isArray(value)) return value;
      if (typeof value.values === "function") return Array.from(value.values());
      return Object.values(value);
    };
    const getChannelName = (channel) => String(
      channel?.name
      || channel?.title
      || channel?.label
      || channel?.channelName
      || ""
    ).trim();
    const getMessageText = (message) => String(
      message?.text
      || message?.message
      || message?.content
      || message?.value
      || message?.plainText
      || message?.renderedText
      || message?.element?.textContent
      || ""
    ).replace(/\\s+/g, " ").trim();
    const getMessageSpeaker = (message) => String(
      message?.speaker
      || message?.author
      || message?.sender
      || message?.name
      || message?.creatureName
      || message?.from
      || ""
    ).replace(/\\s+/g, " ").trim();
    const getMessageMode = (message) => String(
      message?.mode
      || message?.type
      || message?.talkType
      || message?.channelMode
      || ""
    ).trim();
    const getMessageId = (message, index) => String(
      message?.id
      ?? message?.uid
      ?? message?.messageId
      ?? message?.key
      ?? index
    ).trim();
    const getMessageTimestamp = (message) => Number(
      message?.timestamp
      ?? message?.time
      ?? message?.createdAt
      ?? 0
    ) || 0;
    const getOptionText = (option) => String(
      option?.text
      || option?.label
      || option?.title
      || option?.name
      || option?.value
      || option?.caption
      || option?.element?.textContent
      || option
      || ""
    ).replace(/\\s+/g, " ").trim();
    const collectDialogueOptions = () => {
      const collected = [];
      for (const manager of dialogueManagers) {
        for (const source of [
          manager?.options,
          manager?.buttons,
          manager?.choices,
          manager?.entries,
          manager?.menu?.options,
          manager?.currentOptions,
        ]) {
          for (const option of collectValues(source)) {
            if (option && !collected.includes(option)) {
              collected.push(option);
            }
          }
        }
      }

      return collected
        .map((option, index) => ({
          index: Number.isInteger(option?.index) ? option.index : index,
          text: getOptionText(option),
        }))
        .filter((option) => option.text);
    };
    const firstText = (...values) => {
      for (const value of values) {
        const text = String(value || "").replace(/\\s+/g, " ").trim();
        if (text) return text;
      }
      return "";
    };
    const getDialogueOpenState = (options = []) => dialogueManagers.some((manager) => {
      if (!manager) return false;
      if (manager.open === true || manager.visible === true || manager.active === true || manager.isOpen === true) {
        return true;
      }
      if (typeof manager.isOpen === "function") {
        try {
          if (manager.isOpen()) return true;
        } catch {}
      }
      return options.length > 0;
    });
    const getDialogueNpcName = (options = []) => {
      for (const manager of dialogueManagers) {
        const npcName = firstText(
          manager?.npcName,
          manager?.currentNpcName,
          manager?.npc?.name,
          manager?.currentNpc?.name,
          manager?.speaker,
          manager?.creatureName,
          manager?.targetNpcName,
          manager?.title,
        );
        if (npcName) {
          return npcName;
        }
      }

      for (let index = options.length - 1; index >= 0; index -= 1) {
        const optionText = firstText(options[index]?.text);
        if (optionText) {
          const speaker = firstText(optionText.split(":")[0]);
          if (speaker && speaker !== optionText) {
            return speaker;
          }
        }
      }

      return "";
    };
    const getDialoguePrompt = (options = [], recentMessages = []) => {
      for (const manager of dialogueManagers) {
        const prompt = firstText(
          manager?.prompt,
          manager?.message,
          manager?.currentPrompt,
          manager?.currentMessage,
          manager?.question,
          manager?.body,
          manager?.text,
          manager?.label,
        );
        if (prompt) {
          return prompt;
        }
      }

      if (recentMessages.length > 0) {
        return firstText(recentMessages[recentMessages.length - 1]?.text);
      }

      return firstText(options[0]?.text);
    };
    const getTradeManagers = () => [
      game?.interface?.tradeManager,
      game?.interface?.npcTradeManager,
      game?.interface?.shopManager,
      game?.interface?.tradeWindow,
    ].filter(Boolean);
    const getTradeEntries = (keys = []) => {
      const collected = [];
      for (const manager of getTradeManagers()) {
        for (const key of keys) {
          for (const entry of collectValues(manager?.[key])) {
            if (entry && !collected.includes(entry)) {
              collected.push(entry);
            }
          }
        }
      }
      return collected;
    };
    const getTradeState = (options = []) => {
      const managers = getTradeManagers();
      const buyEntries = getTradeEntries(["buyItems", "buyList", "buyOffers", "buyEntries", "items"]);
      const sellEntries = getTradeEntries(["sellItems", "sellList", "sellOffers", "sellEntries", "items"]);
      let selectedItemName = "";
      let selectedItemId = Number.NaN;
      let quantity = Number.NaN;
      let side = "";

      for (const manager of managers) {
        selectedItemName = selectedItemName || firstText(
          manager?.selectedItemName,
          manager?.itemName,
          manager?.selectedItem?.name,
          manager?.selectedItem?.label,
        );
        const managerItemId = Number(
          manager?.selectedItemId
          ?? manager?.itemId
          ?? manager?.selectedItem?.id
          ?? manager?.selectedItem?.itemId,
        );
        if (!Number.isFinite(selectedItemId) && Number.isFinite(managerItemId)) {
          selectedItemId = Math.trunc(managerItemId);
        }
        const managerQuantity = Number(
          manager?.quantity
          ?? manager?.amount
          ?? manager?.count
          ?? manager?.selectedAmount,
        );
        if (!Number.isFinite(quantity) && Number.isFinite(managerQuantity)) {
          quantity = Math.trunc(managerQuantity);
        }
        side = side || firstText(manager?.side, manager?.activeSide, manager?.mode).toLowerCase();
      }

      const open = managers.some((manager) => (
        manager?.open === true
        || manager?.visible === true
        || manager?.active === true
      )) || buyEntries.length > 0
        || sellEntries.length > 0
        || options.some((option) => /\b(?:buy|sell|trade)\b/i.test(option?.text || ""));

      return {
        open,
        side: side === "sell" ? "sell" : (side === "buy" ? "buy" : ""),
        visibleBuyCount: buyEntries.length,
        visibleSellCount: sellEntries.length,
        selectedItemId: Number.isFinite(selectedItemId) ? selectedItemId : null,
        selectedItemName: selectedItemName || null,
        quantity: Number.isFinite(quantity) ? Math.max(0, quantity) : null,
      };
    };

    if (!channelManager) {
      const options = collectDialogueOptions();
      return {
        playerName: firstText(game?.player?.name),
        activeChannelName: "",
        defaultChannelName: "",
        defaultChannelActive: false,
        open: getDialogueOpenState(options),
        npcName: getDialogueNpcName(options),
        prompt: getDialoguePrompt(options, []),
        options,
        tradeState: getTradeState(options),
        travelState: {
          open: options.some((option) => /\b(?:travel|sail|passage|residence)\b/i.test(option?.text || "")),
          destination: null,
          pendingConfirmation: options.some((option) => /^\s*(?:yes|no)\b/i.test(option?.text || "")),
        },
        recentMessages: [],
      };
    }

    const channels = Array.from(collectValues(channelManager.channels || []));
    const defaultChannel = (
      (typeof channelManager.getChannelById === "function" && channelManager.getChannelById(0))
      || (typeof channelManager.getChannel === "function" && channelManager.getChannel("Default"))
      || channels.find((channel) => channel?.id === 0 || getChannelName(channel).toLowerCase() === "default")
      || null
    );
    const activeChannel = typeof channelManager.getActiveChannel === "function"
      ? (channelManager.getActiveChannel() || defaultChannel)
      : defaultChannel;
    const collectChannelMessages = (channel) => {
      const entries = [];
      const sources = [
        channel?.__contents,
        channel?.messages,
        channel?.messageList,
        channel?.history,
        channel?.entries,
        channel?.rows,
        channel?.lines,
      ];

      for (const source of sources) {
        for (const entry of collectValues(source)) {
          if (entry && !entries.includes(entry)) {
            entries.push(entry);
          }
        }
      }

      return entries
        .map((entry, index) => ({
          id: getMessageId(entry, index),
          speaker: getMessageSpeaker(entry),
          mode: getMessageMode(entry),
          text: getMessageText(entry),
          timestamp: getMessageTimestamp(entry),
        }))
        .filter((entry) => entry.text)
        .slice(-${DIALOGUE_RECENT_MESSAGE_LIMIT});
    };
    const collectDialogueRecentMessages = (...messageChannels) => {
      const combined = [];
      const seen = new Set();
      for (const channel of messageChannels) {
        const channelName = getChannelName(channel);
        for (const entry of collectChannelMessages(channel)) {
          const normalized = {
            ...entry,
            channelName,
          };
          const dedupeKey = [
            String(normalized.id || ""),
            String(normalized.timestamp || 0),
            String(normalized.speaker || ""),
            String(normalized.text || ""),
            channelName,
          ].join("|");
          if (seen.has(dedupeKey)) {
            continue;
          }
          seen.add(dedupeKey);
          combined.push(normalized);
        }
      }

      return combined.slice(-${DIALOGUE_RECENT_MESSAGE_LIMIT});
    };
    const messageChannel = defaultChannel || activeChannel || channels.find(Boolean) || null;
    const options = collectDialogueOptions();
    const recentMessages = collectDialogueRecentMessages(
      messageChannel,
      activeChannel && activeChannel !== messageChannel ? activeChannel : null,
    );
    const prompt = getDialoguePrompt(options, recentMessages);
    const npcName = getDialogueNpcName(options) || firstText(
      [...recentMessages].reverse().find((entry) => firstText(entry?.speaker))?.speaker,
    );
    const tradeState = getTradeState(options);
    const travelState = {
      open: /\b(?:travel|sail|passage|residence)\b/i.test(prompt)
        || options.some((option) => /\b(?:travel|sail|passage|residence)\b/i.test(option?.text || "")),
      destination: null,
      pendingConfirmation: /\b(?:would you like|do you want|confirm)\b/i.test(prompt)
        && /\b(?:travel|sail|passage|residence|city|town|temple)\b/i.test(prompt),
    };

    return {
      playerName: firstText(game?.player?.name),
      activeChannelName: getChannelName(activeChannel),
      defaultChannelName: getChannelName(messageChannel),
      defaultChannelActive: Boolean(
        messageChannel
        && activeChannel
        && (
          activeChannel === messageChannel
          || getChannelName(activeChannel).toLowerCase() === getChannelName(messageChannel).toLowerCase()
        )
      ),
      open: getDialogueOpenState(options),
      npcName,
      prompt,
      options,
      tradeState,
      travelState,
      recentMessages,
    };
  })()`;
}

function buildTradeStateExpression() {
  return `(() => {
    const game = window.gameClient;
    const collectValues = (value) => {
      if (!value) return [];
      if (Array.isArray(value)) return value;
      if (typeof value.values === "function") return Array.from(value.values());
      return Object.values(value);
    };
    const normalizeText = (value) => String(value || "").replace(/\\s+/g, " ").trim();
    const getTradeManagers = () => [
      game?.interface?.tradeManager,
      game?.interface?.npcTradeManager,
      game?.interface?.shopManager,
      game?.interface?.tradeWindow,
    ].filter(Boolean);
    const getItemId = (entry) => {
      for (const candidate of [
        entry?.itemId,
        entry?.id,
        entry?.clientId,
        entry?.serverId,
        entry?.item?.id,
        entry?.item?.itemId,
      ]) {
        const numeric = Number(candidate);
        if (Number.isFinite(numeric)) {
          return Math.trunc(numeric);
        }
      }
      return null;
    };
    const getEntryName = (entry) => normalizeText(
      entry?.name
      || entry?.label
      || entry?.title
      || entry?.itemName
      || entry?.item?.name
      || entry
    );
    const getEntryPrice = (entry) => {
      const numeric = Number(entry?.price ?? entry?.cost ?? entry?.value ?? 0);
      return Number.isFinite(numeric) ? Math.max(0, Math.trunc(numeric)) : 0;
    };
    const collectEntries = (side = "buy") => {
      const sourceKeys = side === "sell"
        ? ["sellItems", "sellList", "sellOffers", "sellEntries", "items"]
        : ["buyItems", "buyList", "buyOffers", "buyEntries", "items"];
      const collected = [];
      for (const manager of getTradeManagers()) {
        for (const key of sourceKeys) {
          for (const entry of collectValues(manager?.[key])) {
            if (entry && !collected.includes(entry)) {
              collected.push(entry);
            }
          }
        }
      }
      return collected
        .map((entry, index) => ({
          index,
          itemId: getItemId(entry),
          name: getEntryName(entry),
          price: getEntryPrice(entry),
          side,
        }))
        .filter((entry) => entry.itemId != null || entry.name);
    };
    const inferSide = (manager = {}) => {
      const sideText = normalizeText(
        manager?.activeSide
        || manager?.selectedSide
        || manager?.side
        || manager?.tab
        || manager?.selectedTab
      ).toLowerCase();
      if (sideText.includes("sell")) return "sell";
      if (sideText.includes("buy")) return "buy";
      return "";
    };
    const collectSelectedCandidate = (manager = {}, side = "buy") => {
      const key = side === "sell" ? "sell" : "buy";
      return (
        manager?.selectedItem
        || manager?.currentItem
        || manager?.selectedEntry
        || manager?.[\`selected\${key[0].toUpperCase() + key.slice(1)}Item\`]
        || null
      );
    };
    const managers = getTradeManagers();
    const buyItems = collectEntries("buy");
    const sellItems = collectEntries("sell");
    const primaryManager = managers.find((manager) => (
      manager?.open === true
      || manager?.visible === true
      || buyItems.length > 0
      || sellItems.length > 0
    )) || managers[0] || null;
    const activeSide = inferSide(primaryManager);
    const selectedRaw = primaryManager ? (
      collectSelectedCandidate(primaryManager, activeSide || "buy")
      || collectSelectedCandidate(primaryManager, "buy")
      || collectSelectedCandidate(primaryManager, "sell")
    ) : null;

    return {
      open: Boolean(
        primaryManager?.open === true
        || primaryManager?.visible === true
        || buyItems.length > 0
        || sellItems.length > 0
      ),
      npcName: normalizeText(
        primaryManager?.npcName
        || primaryManager?.sellerName
        || primaryManager?.shopName
      ),
      activeSide,
      selectedItem: selectedRaw
        ? {
            index: Number.isInteger(selectedRaw?.index) ? selectedRaw.index : 0,
            itemId: getItemId(selectedRaw),
            name: getEntryName(selectedRaw),
            price: getEntryPrice(selectedRaw),
            side: activeSide || "buy",
          }
        : null,
      buyItems,
      sellItems,
    };
  })()`;
}

function buildTaskStateExpression() {
  return `(() => {
    const game = window.gameClient;
    const normalizeText = (value) => String(value || "").replace(/\\s+/g, " ").trim();
    const normalizeInteger = (value) => {
      const numeric = Number(value);
      return Number.isFinite(numeric) ? Math.trunc(numeric) : null;
    };
    const managers = [
      game?.interface?.taskManager,
      game?.interface?.dailyTaskManager,
      game?.interface?.questManager,
      game?.taskManager,
      game?.dailyTaskManager,
      game?.questManager,
    ].filter(Boolean);
    const primaryManager = managers.find((manager) => manager?.open === true || manager?.visible === true) || managers[0] || null;
    const progress = primaryManager?.progress || primaryManager?.taskProgress || primaryManager?.currentTask?.progress || null;

    return {
      open: Boolean(primaryManager?.open === true || primaryManager?.visible === true),
      activeTaskType: normalizeText(
        primaryManager?.activeTaskType
        || primaryManager?.taskType
        || primaryManager?.currentTask?.type
      ),
      taskNpc: normalizeText(
        primaryManager?.taskNpc
        || primaryManager?.npcName
        || primaryManager?.currentTask?.npcName
      ),
      taskTarget: normalizeText(
        primaryManager?.taskTarget
        || primaryManager?.target
        || primaryManager?.currentTask?.target
      ),
      progressCurrent: normalizeInteger(
        primaryManager?.progressCurrent
        ?? primaryManager?.current
        ?? progress?.current
      ),
      progressRequired: normalizeInteger(
        primaryManager?.progressRequired
        ?? primaryManager?.required
        ?? progress?.required
      ),
      rewardReady: primaryManager?.rewardReady === true || primaryManager?.canClaimReward === true,
    };
  })()`;
}

function buildWalkExpression(targetPosition) {
  const x = Number(targetPosition.x);
  const y = Number(targetPosition.y);
  const z = Number(targetPosition.z);

  return `(() => {
    const game = window.gameClient;
    const world = game?.world;
    const player = game?.player;
    const pathfinder = world?.pathfinder;
    const PositionCtor = globalThis.Position || player?.__position?.constructor;
    const fallbackPos = { x: ${Number.isFinite(x) ? Math.trunc(x) : 0}, y: ${Number.isFinite(y) ? Math.trunc(y) : 0}, z: ${Number.isFinite(z) ? Math.trunc(z) : 0} };

    if (!game || !world || !player || !pathfinder || typeof pathfinder.findPath !== "function") {
      return { ok: false, reason: "movement unavailable" };
    }

    const toSerializablePosition = (position) => (
      position && Number.isFinite(Number(position.x)) && Number.isFinite(Number(position.y)) && Number.isFinite(Number(position.z))
        ? {
            x: Math.trunc(Number(position.x)),
            y: Math.trunc(Number(position.y)),
            z: Math.trunc(Number(position.z)),
          }
        : null
    );
    const samePosition = (left, right) => Boolean(
      left
      && right
      && Number(left.x) === Number(right.x)
      && Number(left.y) === Number(right.y)
      && Number(left.z) === Number(right.z)
    );
    const from = player.__position;
    const to = typeof PositionCtor === "function"
      ? new PositionCtor(fallbackPos.x, fallbackPos.y, fallbackPos.z)
      : fallbackPos;

    try {
      pathfinder.findPath(from, to);
    } catch (error) {
      return {
        ok: false,
        reason: "pathfinder error",
        message: error?.message || String(error || ""),
      };
    }

    const finalDestination = toSerializablePosition(pathfinder?.__finalDestination);
    const autoWalkStepsRemaining = Math.max(0, Number(pathfinder?.__autoWalkStepsRemaining) || 0);
    const autoWalking = Boolean(
      pathfinder?.__isAutoWalking
      || autoWalkStepsRemaining > 0
      || (typeof player?.isAutoWalking === "function" && player.isAutoWalking())
    );
    if (!autoWalking && autoWalkStepsRemaining <= 0 && !samePosition(finalDestination, fallbackPos)) {
      return {
        ok: false,
        reason: "path not accepted",
        destination: { x: to.x, y: to.y, z: to.z },
        playerPosition: from ? { x: from.x, y: from.y, z: from.z } : null,
        finalDestination,
        autoWalkStepsRemaining,
        autoWalking,
      };
    }

    return {
      ok: true,
      destination: { x: to.x, y: to.y, z: to.z },
      playerPosition: from ? { x: from.x, y: from.y, z: from.z } : null,
      finalDestination,
      autoWalkStepsRemaining,
      autoWalking,
    };
  })()`;
}

function buildViewportClickPositionExpression(targetPosition) {
  const x = Number(targetPosition.x);
  const y = Number(targetPosition.y);
  const z = Number(targetPosition.z);

  return `(() => {
    const game = window.gameClient;
    const player = game?.player;
    const renderer = game?.renderer;
    const screenManager = game?.interface?.screenElementManager;
    const screen = screenManager?.screen
      || screenManager?.screenCanvas
      || document.getElementById("screen")
      || screenManager?.screenWrapper?.querySelector?.("canvas")
      || document.querySelector("canvas#screen, #screen, #wrapper canvas, canvas");
    const wrapper = screenManager?.screenWrapper
      || screen?.parentElement
      || screen?.closest?.("#wrapper, .screen-wrapper, .game-screen, [data-screen-wrapper]")
      || document.getElementById("wrapper");
    const target = { x: ${Number.isFinite(x) ? Math.trunc(x) : 0}, y: ${Number.isFinite(y) ? Math.trunc(y) : 0}, z: ${Number.isFinite(z) ? Math.trunc(z) : 0} };
    const wrapperRect = wrapper?.getBoundingClientRect?.();
    const screenRect = screen?.getBoundingClientRect?.();
    const rect = wrapperRect?.width > 0 && wrapperRect?.height > 0
      ? wrapperRect
      : screenRect;

    if (!game || !player?.__position || !renderer || !screen || !rect || typeof renderer.getStaticScreenPosition !== "function") {
      return { ok: false, reason: "viewport click unavailable" };
    }

    if (Number(player.__position.z) !== Number(target.z)) {
      return {
        ok: false,
        reason: "target floor not visible",
        target,
        playerPosition: { x: player.__position.x, y: player.__position.y, z: player.__position.z },
      };
    }

    const projected = renderer.getStaticScreenPosition(target);
    const columns = Math.max(1, Math.round((screen.width || 0) / 32) || 15);
    const rows = Math.max(1, Math.round((screen.height || 0) / 32) || 11);

    if (!projected || projected.x < 0 || projected.x >= columns || projected.y < 0 || projected.y >= rows) {
      return {
        ok: false,
        reason: "target outside viewport",
        target,
        projected,
        columns,
        rows,
      };
    }

    const tileWidth = rect.width / columns;
    const tileHeight = rect.height / rows;
    return {
      ok: true,
      target,
      projected,
      x: rect.left + (projected.x + 0.5) * tileWidth,
      y: rect.top + (projected.y + 0.5) * tileHeight,
      columns,
      rows,
    };
  })()`;
}

function buildCastWordsExpression(words) {
  const castWords = JSON.stringify(String(words || "").trim());

  return `(() => {
    const game = window.gameClient;
    const player = game?.player;
    const ui = game?.interface;
    const hotbar = ui?.hotbarManager;
    const channelManager = ui?.channelManager;
    const text = ${castWords};
    const PacketCtor = globalThis.ChannelMessagePacket;
    const defaultChannel = globalThis.CONST?.CHANNEL?.DEFAULT;
    const canUseChannelManager = Boolean(
      channelManager && typeof channelManager.sendMessageText === "function"
    );
    const canUsePacketCtor = typeof game?.send === "function"
      && typeof PacketCtor === "function"
      && defaultChannel != null;
    const canUseHotbarSpellHandler = Boolean(
      hotbar && typeof hotbar.__handleSpellUseWithMode === "function"
    );

    if (!game || !player || !ui || !text) {
      return { ok: false, reason: "cast unavailable" };
    }

    const entries = ui.SPELLS ? Array.from(ui.SPELLS.entries()) : [];
    const match = entries.find((entry) => {
      const spell = entry[1];
      return spell && spell.words && spell.words.toLowerCase() === text.toLowerCase();
    });

    if (match) {
      const sid = Number(match[0]);
      const spell = match[1];
      const spellbook = player.spellbook;
      const globalCooldown = spellbook?.GLOBAL_COOLDOWN;
      const cooldowns = spellbook?.cooldowns;

      const hasGlobalCooldown = Boolean(cooldowns && cooldowns.has(globalCooldown));
      const hasSpellCooldown = Boolean(cooldowns && cooldowns.has(sid));
      if (hasGlobalCooldown || hasSpellCooldown) {
        return {
          ok: false,
          reason: "cooldown",
          cooldownScope: hasGlobalCooldown ? "global" : "spell",
          sid,
          words: text,
        };
      }

      if (spell.mana && (player.state?.mana || 0) < spell.mana) {
        return { ok: false, reason: "low mana", sid, words: text };
      }

      if (hotbar && hotbar.__canPlayerCastSpell && !hotbar.__canPlayerCastSpell(sid)) {
        return { ok: false, reason: "requirements", sid, words: text };
      }

      if (canUseHotbarSpellHandler) {
        hotbar.__handleSpellUseWithMode({ sid, words: text }, "bot");
        return {
          ok: true,
          words: text,
          sid,
          spell: spell.name,
          transport: "hotbar",
        };
      }
    }

    if (canUseChannelManager) {
      channelManager.sendMessageText(
        text,
        defaultChannel == null ? undefined : defaultChannel,
      );
      return {
        ok: true,
        words: text,
        sid: match ? Number(match[0]) : null,
        spell: match ? match[1].name : text,
        transport: "channelManager",
        channelId: defaultChannel == null ? null : defaultChannel,
      };
    }

    if (canUsePacketCtor) {
      game.send(new PacketCtor(defaultChannel, 1, text));

      return {
        ok: true,
        words: text,
        sid: match ? Number(match[0]) : null,
        spell: match ? match[1].name : text,
        transport: "packet",
      };
    }

    if (match && typeof player.spellbook?.castSpell === "function") {
      const sid = Number(match[0]);
      const spell = match[1];

      player.spellbook.castSpell(sid);
      return {
        ok: true,
        words: text,
        sid,
        spell: spell.name,
        transport: "spellbook",
      };
    }

    return {
      ok: false,
      reason: "cast unavailable",
      words: text,
      sid: match ? Number(match[0]) : null,
      spell: match ? match[1].name : text,
    };
  })()`;
}

function buildUseHotbarSlotExpression(slotIndex, options = {}) {
  const normalizedSlotIndex = Math.max(0, Math.trunc(Number(slotIndex) || 0));
  const mode = JSON.stringify(String(options?.mode || "bot").trim() || "bot");
  const target = JSON.stringify(String(options?.target || "").trim().toLowerCase());

  return `(async () => {
    const game = window.gameClient;
    const ui = game?.interface;
    const hotbar = ui?.hotbarManager;
    const requestedSlotIndex = ${normalizedSlotIndex};
    const requestedMode = ${mode};
    const requestedTarget = ${target};
    const PacketCtor = globalThis.ChannelMessagePacket;
    const defaultChannel = globalThis.CONST?.CHANNEL?.DEFAULT;
    const ItemUseOnCreaturePacketCtor = globalThis.ItemUseOnCreaturePacket || globalThis.ItemUseCreaturePacket;
    const collectValues = (value) => {
      if (!value) return [];
      if (Array.isArray(value)) return value;
      if (typeof value.values === "function") return Array.from(value.values());
      return Object.values(value);
    };
    const collectTexts = (value, depth = 0, seen = new Set()) => {
      if (value == null || depth > 2) return [];
      if (typeof value === "string" || typeof value === "number" || typeof value === "boolean") {
        return [String(value)];
      }
      if (typeof value !== "object" || seen.has(value)) return [];
      seen.add(value);
      if (Array.isArray(value)) {
        return value.flatMap((entry) => collectTexts(entry, depth + 1, seen));
      }

      const texts = [];
      for (const [key, entry] of Object.entries(value)) {
        if (/^(which|owner|parent|item|items|slots|slot|container|equipment)$/i.test(key)) continue;
        texts.push(String(key));
        texts.push(...collectTexts(entry, depth + 1, seen));
      }
      return texts;
    };
    const getItemId = (item) => {
      const itemId = Number(item?.id ?? item?.itemId ?? item?.clientId ?? item?.serverId);
      return Number.isFinite(itemId) ? itemId : null;
    };
    const getItemCount = (item) => {
      if (!item) return 0;
      const rawCount = Number(item?.count ?? item?.amount ?? item?.charges ?? item?.quantity);
      if (Number.isFinite(rawCount) && rawCount > 0) {
        return Math.trunc(rawCount);
      }
      return 1;
    };
    const getHotbarEntries = () => {
      const groups = [
        hotbar?.slots,
        hotbar?.__slots,
        hotbar?.hotbarSlots,
        hotbar?.__hotbarSlots,
        ui?.hotbar?.slots,
        ui?.hotbarSlots,
      ];
      for (const group of groups) {
        const entries = collectValues(group);
        if (entries.length > 0) return entries;
      }
      return [];
    };
    const getSlotItem = (slot) => (
      slot?.item
      || slot?.linkedItem
      || slot?.payload?.item
      || slot?.content?.item
      || null
    );
    const getSlotLabel = (slot) => {
      const item = getSlotItem(slot);
      return String(
        slot?.label
        || slot?.name
        || slot?.spell?.name
        || item?.name
        || slot?.words
        || slot?.text
        || slot?.message
        || slot?.macro
        || "",
      ).trim();
    };
    const getSlotKind = (slot) => {
      const item = getSlotItem(slot);
      const explicitTexts = [
        slot?.type,
        slot?.kind,
        slot?.action,
        slot?.name,
        slot?.label,
        slot?.mode,
        slot?.words,
        slot?.text,
        slot?.message,
        slot?.macro,
        slot?.spellName,
        slot?.spell?.name,
      ]
        .map((value) => String(value || "").trim())
        .filter(Boolean)
        .join(" ")
        .toLowerCase();
      const hasSpell = Number.isFinite(Number(slot?.sid ?? slot?.spellId ?? slot?.spell?.id))
        || Boolean(slot?.spell)
        || Boolean(String(slot?.spellName || "").trim());
      const hasItem = getItemId(item) != null || Boolean(item);
      const hasMacroText = Boolean(
        String(slot?.text || "").trim()
        || String(slot?.message || "").trim()
        || String(slot?.macro || "").trim()
        || (String(slot?.words || "").trim() && !hasSpell && !hasItem)
      );

      if (/attack nearest|nearest attack/.test(explicitTexts)) return "attack-nearest";
      if (hasSpell || explicitTexts.includes("spell")) return "spell";
      if (hasItem || explicitTexts.includes("item")) return "item";
      if (hasMacroText || explicitTexts.includes("macro") || explicitTexts.includes("message") || explicitTexts.includes("text")) return "text";
      return explicitTexts ? explicitTexts.split(/\\s+/)[0] : null;
    };
    const tryCall = (owner, methodNames, args = []) => {
      for (const methodName of methodNames) {
        if (typeof owner?.[methodName] !== "function") continue;
        try {
          owner[methodName](...args);
          return methodName;
        } catch {}
      }
      return "";
    };

    if (!hotbar) {
      return { ok: false, reason: "hotbar unavailable", slotIndex: requestedSlotIndex };
    }

    const entries = getHotbarEntries();
    const slot = entries[requestedSlotIndex]
      || entries.find((entry) => Number(entry?.slotIndex ?? entry?.index) === requestedSlotIndex)
      || null;
    if (!slot) {
      return { ok: false, reason: "hotbar slot unavailable", slotIndex: requestedSlotIndex };
    }

    const item = getSlotItem(slot);
    const spellId = Number(slot?.sid ?? slot?.spellId ?? slot?.spell?.id);
    const words = String(slot?.words ?? slot?.text ?? slot?.message ?? slot?.macro ?? slot?.spell?.words ?? "").trim();
    const kind = getSlotKind(slot);
    const label = getSlotLabel(slot);
    const isCooldownActive = Boolean(slot?.cooldownActive === true || slot?.onCooldown === true || slot?.cooldown === true);

    if (isCooldownActive) {
      return {
        ok: false,
        reason: "cooldown",
        slotIndex: requestedSlotIndex,
        kind,
        label,
      };
    }

    if (item && (requestedTarget === "self" || requestedTarget === "target")) {
      const useTarget = requestedTarget === "self"
        ? game?.player
        : game?.player?.__target || null;
      const itemId = getItemId(item);
      const itemRef = {
        which: hotbar,
        index: requestedSlotIndex,
        location: "hotbar",
        containerRuntimeId: null,
        item,
      };

      if (!useTarget) {
        return {
          ok: false,
          reason: "target unavailable",
          slotIndex: requestedSlotIndex,
          kind: kind || "item",
          label,
          itemId,
          target: requestedTarget,
        };
      }

      for (const ref of [itemRef, slot, item]) {
        const mouseTargetMethod = tryCall(game?.mouse, [
          "useOnCreature",
          "sendItemUseOnCreature",
          "useItemOnCreature",
        ], [ref, useTarget]);
        if (mouseTargetMethod) {
          return {
            ok: true,
            slotIndex: requestedSlotIndex,
            kind: kind || "item",
            label,
            itemId,
            count: getItemCount(item),
            target: requestedTarget,
            transport: mouseTargetMethod,
          };
        }
      }

      if (typeof game?.send === "function" && typeof ItemUseOnCreaturePacketCtor === "function") {
        game.send(new ItemUseOnCreaturePacketCtor(itemRef, useTarget));
        return {
          ok: true,
          slotIndex: requestedSlotIndex,
          kind: kind || "item",
          label,
          itemId,
          count: getItemCount(item),
          target: requestedTarget,
          transport: "item-use-on-creature-packet",
        };
      }

      for (const [owner, methodNames, args] of [
        [item, ["useOnCreature", "useWith", "onUseWith", "__useWith", "use", "onUse", "__use"], [useTarget]],
        [hotbar, ["useOnCreature", "useItemOnCreature"], [requestedSlotIndex, useTarget, slot]],
      ]) {
        const targetMethod = tryCall(owner, methodNames, args);
        if (targetMethod) {
          return {
            ok: true,
            slotIndex: requestedSlotIndex,
            kind: kind || "item",
            label,
            itemId,
            count: getItemCount(item),
            target: requestedTarget,
            transport: targetMethod,
          };
        }
      }

      return {
        ok: false,
        reason: "self-target item use unavailable",
        slotIndex: requestedSlotIndex,
        kind: kind || "item",
        label,
        itemId,
        target: requestedTarget,
      };
    }

    if (Number.isFinite(spellId)) {
      if (typeof hotbar?.__canPlayerCastSpell === "function" && !hotbar.__canPlayerCastSpell(spellId)) {
        return {
          ok: false,
          reason: "requirements",
          slotIndex: requestedSlotIndex,
          kind,
          label,
          sid: spellId,
          words,
        };
      }

      if (typeof hotbar?.__handleSpellUseWithMode === "function") {
        hotbar.__handleSpellUseWithMode({ sid: spellId, words }, requestedMode);
        return {
          ok: true,
          slotIndex: requestedSlotIndex,
          kind: "spell",
          label,
          sid: spellId,
          words,
          transport: "hotbar-spell",
        };
      }
    }

    const hotbarMethod = tryCall(hotbar, [
      "useSlot",
      "__useSlot",
      "activateSlot",
      "__activateSlot",
      "handleUseSlot",
      "__handleUseSlot",
      "handleSlotUse",
      "__handleSlotUse",
      "triggerSlot",
      "__triggerSlot",
      "executeSlot",
      "__executeSlot",
    ], [requestedSlotIndex, requestedMode, slot]);
    if (hotbarMethod) {
      return {
        ok: true,
        slotIndex: requestedSlotIndex,
        kind,
        label,
        sid: Number.isFinite(spellId) ? spellId : null,
        words,
        itemId: getItemId(item),
        transport: hotbarMethod,
      };
    }

    const slotMethod = tryCall(slot, [
      "use",
      "activate",
      "trigger",
      "execute",
      "onUse",
    ], [requestedMode, game?.player]);
    if (slotMethod) {
      return {
        ok: true,
        slotIndex: requestedSlotIndex,
        kind,
        label,
        sid: Number.isFinite(spellId) ? spellId : null,
        words,
        itemId: getItemId(item),
        transport: slotMethod,
      };
    }

    if (kind === "attack-nearest") {
      const attackMethod = (
        tryCall(game?.battleManager, ["attackNearest"], [])
        || tryCall(game?.battle, ["attackNearest"], [])
        || tryCall(game?.player, ["attackNearest"], [])
        || tryCall(game, ["attackNearest"], [])
      );
      if (attackMethod) {
        return {
          ok: true,
          slotIndex: requestedSlotIndex,
          kind,
          label,
          transport: attackMethod,
        };
      }
    }

    if (words && typeof game?.send === "function" && typeof PacketCtor === "function" && defaultChannel != null) {
      game.send(new PacketCtor(defaultChannel, 1, words));
      return {
        ok: true,
        slotIndex: requestedSlotIndex,
        kind: kind || "text",
        label,
        words,
        transport: "packet",
      };
    }

    if (item && typeof game?.mouse?.use === "function") {
      game.mouse.use(slot);
      return {
        ok: true,
        slotIndex: requestedSlotIndex,
        kind: kind || "item",
        label,
        itemId: getItemId(item),
        transport: "mouse-use",
      };
    }

    return {
      ok: false,
      reason: "slot execution unavailable",
      slotIndex: requestedSlotIndex,
      kind,
      label,
      sid: Number.isFinite(spellId) ? spellId : null,
      words,
      itemId: getItemId(item),
    };
  })()`;
}

function buildUseConsumableExpression(options = {}) {
  const itemId = options?.itemId == null ? Number.NaN : Number(options.itemId);
  const name = JSON.stringify(String(options?.name || "").trim().toLowerCase());
  const category = JSON.stringify(String(options?.category || "").trim().toLowerCase());
  const target = JSON.stringify(String(options?.target || "").trim().toLowerCase());

  return `(async () => {
    const game = window.gameClient;
    const player = game?.player;
    const ItemUsePacketCtor = globalThis.ItemUsePacket;
    const ItemUseOnCreaturePacketCtor = globalThis.ItemUseOnCreaturePacket || globalThis.ItemUseCreaturePacket;
    const requestedItemId = ${Number.isFinite(itemId) ? Math.trunc(itemId) : "Number.NaN"};
    const requestedName = ${name};
    const requestedCategory = ${category};
    const requestedTarget = ${target};
    const collectValues = (value) => {
      if (!value) return [];
      if (Array.isArray(value)) return value;
      if (typeof value.values === "function") return Array.from(value.values());
      return Object.values(value);
    };
    const getItemId = (item) => {
      const value = Number(item?.id ?? item?.itemId ?? item?.clientId ?? item?.serverId);
      return Number.isFinite(value) ? value : null;
    };
    const getItemCount = (item) => {
      if (!item) return 0;
      const rawCount = Number(item?.count ?? item?.amount ?? item?.charges ?? item?.quantity);
      if (Number.isFinite(rawCount) && rawCount > 0) {
        return Math.trunc(rawCount);
      }
      return 1;
    };
    const getItemName = (item) => String(
      item?.name
      || item?.type?.name
      || item?.itemType?.name
      || item?.description
      || "",
    ).trim();
    const getItemCategory = (item) => {
      const label = getItemName(item).toLowerCase();
      if (!label) return "";
      if (/arrow|bolt|spear|ammunition|ammo/.test(label)) return "ammo";
      if (/potion|fluid/.test(label)) return "potion";
      if (/rune/.test(label)) return "rune";
      if (/\\brope\\b/.test(label)) return "rope";
      if (/shovel/.test(label)) return "shovel";
      if (/food|ham|meat|fish|salmon|mushroom|bread|cheese|banana|apple|cookie/.test(label)) return "food";
      return "";
    };
    const getEquipmentEntries = () => {
      const equipment = player?.equipment;
      const slots = Array.isArray(equipment?.slots) ? equipment.slots : [];
      const entries = [];
      if (!equipment || typeof equipment.getSlotItem !== "function") return entries;
      for (let slotIndex = 0; slotIndex < slots.length; slotIndex += 1) {
        const item = equipment.getSlotItem(slotIndex);
        if (!item) continue;
        entries.push({
          which: equipment,
          index: slotIndex,
          location: "equipment",
          containerRuntimeId: null,
          item,
        });
      }
      return entries;
    };
    const getContainerEntries = () => {
      const containers = Array.from(player?.__openedContainers || [])
        .filter((container) => container && Array.isArray(container.slots) && typeof container.getSlotItem === "function");
      const entries = [];
      for (const container of containers) {
        for (let slotIndex = 0; slotIndex < container.slots.length; slotIndex += 1) {
          const item = container.getSlotItem(slotIndex);
          if (!item) continue;
          entries.push({
            which: container,
            index: slotIndex,
            location: "container",
            containerRuntimeId: Number(container?.__containerId) || null,
            item,
          });
        }
      }
      return entries;
    };
    const interruptAutoWalkForInventory = () => {
      const world = game?.world;
      const pathfinder = world?.pathfinder;
      const otcGame = globalThis.g_game;
      for (const [owner, methodName] of [
        [player, "stopAutoWalk"],
        [player, "cancelAutoWalk"],
        [pathfinder, "stopAutoWalk"],
        [pathfinder, "cancelAutoWalk"],
        [game, "stop"],
        [otcGame, "stop"],
      ]) {
        if (!owner || typeof owner[methodName] !== "function") continue;
        try {
          owner[methodName]();
        } catch {}
      }
    };
    const matchesRequest = (entry) => {
      const entryItemId = getItemId(entry?.item);
      const entryName = getItemName(entry?.item).toLowerCase();
      const entryCategory = getItemCategory(entry?.item);
      if (Number.isFinite(requestedItemId) && entryItemId !== requestedItemId) {
        return false;
      }
      if (requestedName && !entryName.includes(requestedName)) {
        return false;
      }
      if (requestedCategory && entryCategory !== requestedCategory) {
        return false;
      }
      return true;
    };
    const tryCall = (owner, methodNames, args = []) => {
      for (const methodName of methodNames) {
        if (typeof owner?.[methodName] !== "function") continue;
        try {
          owner[methodName](...args);
          return methodName;
        } catch {}
      }
      return "";
    };

    if (!game || !player) {
      return { ok: false, reason: "game unavailable" };
    }

    const found = [...getEquipmentEntries(), ...getContainerEntries()].find(matchesRequest) || null;
    if (!found) {
      return {
        ok: false,
        reason: "consumable not found",
        itemId: Number.isFinite(requestedItemId) ? requestedItemId : null,
        name: requestedName || "",
        category: requestedCategory || "",
      };
    }

    interruptAutoWalkForInventory();
    const entryItemId = getItemId(found.item);
    const entryName = getItemName(found.item);
    const entryCategory = getItemCategory(found.item);
    const useTarget = requestedTarget === "self"
      ? player
      : requestedTarget === "target"
        ? player?.__target || null
        : null;

    if (useTarget) {
      const mouseTargetMethod = tryCall(game?.mouse, [
        "useOnCreature",
        "sendItemUseOnCreature",
        "useItemOnCreature",
      ], [found, useTarget]);
      if (mouseTargetMethod) {
        return {
          ok: true,
          itemId: entryItemId,
          name: entryName,
          count: getItemCount(found.item),
          category: entryCategory || null,
          location: found.location,
          slotIndex: found.index,
          containerRuntimeId: found.containerRuntimeId,
          target: requestedTarget,
          transport: mouseTargetMethod,
        };
      }

      if (typeof game?.send === "function" && typeof ItemUseOnCreaturePacketCtor === "function") {
        game.send(new ItemUseOnCreaturePacketCtor(found, useTarget));
        return {
          ok: true,
          itemId: entryItemId,
          name: entryName,
          count: getItemCount(found.item),
          category: entryCategory || null,
          location: found.location,
          slotIndex: found.index,
          containerRuntimeId: found.containerRuntimeId,
          target: requestedTarget,
          transport: "item-use-on-creature-packet",
        };
      }
    }

    const directItemMethod = tryCall(found.item, ["use", "onUse", "__use"], [useTarget || player]);
    if (directItemMethod) {
      return {
        ok: true,
        itemId: entryItemId,
        name: entryName,
        count: getItemCount(found.item),
        category: entryCategory || null,
        location: found.location,
        slotIndex: found.index,
        containerRuntimeId: found.containerRuntimeId,
        target: requestedTarget || null,
        transport: directItemMethod,
      };
    }

    if (typeof game?.mouse?.use === "function") {
      game.mouse.use(found);
      return {
        ok: true,
        itemId: entryItemId,
        name: entryName,
        count: getItemCount(found.item),
        category: entryCategory || null,
        location: found.location,
        slotIndex: found.index,
        containerRuntimeId: found.containerRuntimeId,
        target: requestedTarget || null,
        transport: "mouse-use",
      };
    }

    if (typeof game?.send === "function" && typeof ItemUsePacketCtor === "function") {
      game.send(new ItemUsePacketCtor(found));
      return {
        ok: true,
        itemId: entryItemId,
        name: entryName,
        count: getItemCount(found.item),
        category: entryCategory || null,
        location: found.location,
        slotIndex: found.index,
        containerRuntimeId: found.containerRuntimeId,
        target: requestedTarget || null,
        transport: "item-use-packet",
      };
    }

    return {
      ok: false,
      reason: "consumable use unavailable",
      itemId: entryItemId,
      name: entryName,
      category: entryCategory || null,
      location: found.location,
      slotIndex: found.index,
      containerRuntimeId: found.containerRuntimeId,
      target: requestedTarget || null,
    };
  })()`;
}

function buildConvertCurrencyExpression(options = {}) {
  const maxAttempts = Math.max(1, Math.min(3, Math.trunc(Number(options?.maxAttempts) || 1)));
  const goldOnly = options?.goldOnly === true;
  const coinIds = Array.isArray(options?.coinIds)
    ? options.coinIds.map((value) => Number(value)).filter((value) => value === GOLD_COIN_ID || value === PLATINUM_COIN_ID)
    : goldOnly
      ? [GOLD_COIN_ID]
      : [GOLD_COIN_ID, PLATINUM_COIN_ID];
  const includePlatinumPlaceholder = options?.includePlatinumPlaceholder !== false;
  const routeCurrencyPlaceholder = options?.routeCurrencyPlaceholder === true;
  const allowStandaloneValueSlotRouting = options?.allowStandaloneValueSlotRouting === true;
  const preferredValueSlotKind = typeof options?.preferredValueSlotKind === "string"
    ? options.preferredValueSlotKind
    : "";
  const preferredValueSlotIndex = Number(options?.preferredValueSlotIndex);
  const preferredValueContainerRuntimeId = Number(options?.preferredValueContainerRuntimeId);

  return `(async () => {
    const game = window.gameClient;
    const hotbar = game?.interface?.hotbarManager;
    const goldCoinId = ${GOLD_COIN_ID};
    const platinumCoinId = ${PLATINUM_COIN_ID};
    const crystalCoinId = ${CRYSTAL_COIN_ID};
    const backpackSlotIndex = ${BACKPACK_EQUIPMENT_SLOT_INDEX};
    const valueEquipmentSlotIndex = ${CURRENCY_PLACEHOLDER_SLOT_INDEX};
    const maxAttempts = ${maxAttempts};
    const coinIds = ${JSON.stringify(coinIds)};
    const includePlatinumPlaceholder = ${includePlatinumPlaceholder};
    const routeCurrencyPlaceholder = ${routeCurrencyPlaceholder};
    const allowStandaloneValueSlotRouting = ${allowStandaloneValueSlotRouting};
    const preferredValueSlotKind = ${JSON.stringify(preferredValueSlotKind)};
    const preferredValueSlotIndex = ${Number.isFinite(preferredValueSlotIndex) ? Math.trunc(preferredValueSlotIndex) : "Number.NaN"};
    const preferredValueContainerRuntimeId = ${Number.isFinite(preferredValueContainerRuntimeId) ? Math.trunc(preferredValueContainerRuntimeId) : "Number.NaN"};
    const ItemUsePacketCtor = globalThis.ItemUsePacket;
    const ItemMovePacketCtor = globalThis.ItemMovePacket;
    const shovelIds = new Set(${JSON.stringify(SHOVEL_TOOL_IDS)});
    const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, Math.max(0, Number(ms) || 0)));
    const interruptAutoWalkForInventory = () => {
      const world = game?.world;
      const player = game?.player;
      const pathfinder = world?.pathfinder;
      const otcGame = globalThis.g_game;
      const hadAutoWalk = Boolean(
        pathfinder?.__isAutoWalking
        || pathfinder?.__finalDestination
        || Number(pathfinder?.__autoWalkStepsRemaining) > 0
        || (typeof player?.isAutoWalking === "function" && player.isAutoWalking())
        || (typeof player?.isMoving === "function" && player.isMoving())
      );
      if (!hadAutoWalk) return false;

      let interruptedWalk = false;
      for (const [owner, methodName] of [
        [player, "stopAutoWalk"],
        [player, "cancelAutoWalk"],
        [pathfinder, "stopAutoWalk"],
        [pathfinder, "cancelAutoWalk"],
        [game, "stop"],
        [otcGame, "stop"],
      ]) {
        if (!owner || typeof owner[methodName] !== "function") continue;
        try {
          owner[methodName]();
          interruptedWalk = true;
        } catch {}
      }

      if (pathfinder && typeof pathfinder === "object") {
        try {
          if (Object.prototype.hasOwnProperty.call(pathfinder, "__isAutoWalking")) {
            pathfinder.__isAutoWalking = false;
          }
        } catch {}
        try {
          if (Object.prototype.hasOwnProperty.call(pathfinder, "__finalDestination")) {
            pathfinder.__finalDestination = null;
          }
        } catch {}
        try {
          if (Object.prototype.hasOwnProperty.call(pathfinder, "__autoWalkStepsRemaining")) {
            pathfinder.__autoWalkStepsRemaining = 0;
          }
        } catch {}
      }

      return interruptedWalk;
    };

    if (!hotbar || typeof hotbar.__findFullCoinStack !== "function" || typeof hotbar.__convertCurrency !== "function") {
      return { ok: false, reason: "hotbar unavailable" };
    }

    const getCurrencyPlaceholderSlotIndex = () => ${buildCurrencyPlaceholderSlotIndexExpression(
    "game?.player?.equipment",
    "valueEquipmentSlotIndex",
  )};
    const getBackpackEquipmentSlotIndex = () => ${buildBackpackEquipmentSlotIndexExpression(
    "game?.player?.equipment",
    "backpackSlotIndex",
  )};
    const getItemId = (item) => {
      const itemId = Number(item?.id ?? item?.itemId ?? item?.clientId ?? item?.serverId);
      return Number.isFinite(itemId) ? itemId : null;
    };
    const getItemCount = (item) => Math.max(0, Math.trunc(Number(item?.count) || 0));
    const getItemLabel = (item) => (
      [
        item?.name,
        item?.type?.name,
        item?.itemType?.name,
        item?.description,
        item?.constructor?.name,
      ]
        .filter(Boolean)
        .join(" ")
        .toLowerCase()
    );
    const isValueSlotMarkerItem = (item) => {
      const itemId = getItemId(item);
      const itemLabel = getItemLabel(item);
      const isGreatFireballRune = (
        itemLabel.includes("${GREAT_FIREBALL_RUNE_LABEL}")
        || itemLabel.includes("${GREAT_FIREBALL_RUNE_ABBREVIATION}")
      ) && itemLabel.includes("rune");
      return (itemId != null && shovelIds.has(itemId)) || itemLabel.includes("shovel") || isGreatFireballRune;
    };
    const getEquipmentSlotItem = (slotIndex) => {
      const equipment = game?.player?.equipment;
      if (!equipment || typeof equipment.getSlotItem !== "function") return null;
      return equipment.getSlotItem(slotIndex);
    };
    const getContainers = () => Array.from(game?.player?.__openedContainers || [])
      .filter((container) => container && Array.isArray(container.slots) && typeof container.getSlotItem === "function");
    const getPrimaryBackpackContainer = (containers = getContainers()) => {
      const backpackItem = getEquipmentSlotItem(getBackpackEquipmentSlotIndex());
      const backpackItemId = getItemId(backpackItem);
      const matchingContainers = containers.filter((container) => getItemId(container) === backpackItemId);
      return matchingContainers[matchingContainers.length - 1]
        || containers[containers.length - 1]
        || null;
    };
    const createEquipmentSlotInfo = (slotIndex) => {
      const equipment = game?.player?.equipment;
      const slots = Array.isArray(equipment?.slots) ? equipment.slots : null;
      if (!equipment || !slots || typeof equipment.getSlotItem !== "function" || slotIndex < 0 || slotIndex >= slots.length) return null;
      const item = equipment.getSlotItem(slotIndex);
      return {
        kind: "equipment",
        which: equipment,
        equipment,
        container: null,
        slotIndex,
        item,
        itemId: getItemId(item),
        count: getItemCount(item),
        hasValueMarker: isValueSlotMarkerItem(item),
      };
    };
    const createContainerSlotInfo = (container, slotIndex) => {
      const slots = Array.isArray(container?.slots) ? container.slots : null;
      if (!container || !slots || typeof container.getSlotItem !== "function" || slotIndex < 0 || slotIndex >= slots.length) return null;
      const item = container.getSlotItem(slotIndex);
      return {
        kind: "container",
        which: container,
        equipment: null,
        container,
        slotIndex,
        item,
        itemId: getItemId(item),
        count: getItemCount(item),
        hasValueMarker: isValueSlotMarkerItem(item),
      };
    };
    const slotHasValueMarker = (slot) => Boolean(slot?.hasValueMarker === true);
    const slotHasValueSignature = (slot) => Boolean(
      slot
      && (
        slotHasValueMarker(slot)
        || slot.itemId === platinumCoinId
        || slot.itemId === crystalCoinId
      )
    );
    const slotHasValueCoins = (slot) => Boolean(
      slot
      && (
        slot.itemId === platinumCoinId
        || slot.itemId === crystalCoinId
      )
    );
    const getValueCoinPriority = (slot) => (
      slot?.itemId === crystalCoinId
        ? 2
        : slot?.itemId === platinumCoinId
          ? 1
          : 0
    );
    const preferValueCoinSlot = (currentBest, candidate) => {
      if (!slotHasValueCoins(candidate)) return currentBest;
      if (!slotHasValueCoins(currentBest)) return candidate;

      const currentPriority = getValueCoinPriority(currentBest);
      const candidatePriority = getValueCoinPriority(candidate);
      if (candidatePriority !== currentPriority) {
        return candidatePriority > currentPriority ? candidate : currentBest;
      }

      if (candidate.count !== currentBest.count) {
        return candidate.count > currentBest.count ? candidate : currentBest;
      }

      if (candidate.kind !== currentBest.kind) {
        return candidate.kind === "equipment" ? candidate : currentBest;
      }

      return currentBest;
    };
    const isSameSlot = (slot, kind, owner, slotIndex) => Boolean(
      slot
      && slot.kind === kind
      && slot.slotIndex === slotIndex
      && (
        (kind === "equipment" && slot.equipment === owner)
        || (kind === "container" && slot.container === owner)
      )
    );
    const hasValueCoinsOutsideSlot = (slot, containers = getContainers()) => {
      const equipmentSlots = Array.isArray(game?.player?.equipment?.slots) ? game.player.equipment.slots : [];
      for (let slotIndex = 0; slotIndex < equipmentSlots.length; slotIndex += 1) {
        if (isSameSlot(slot, "equipment", game?.player?.equipment, slotIndex)) continue;
        const itemId = getItemId(getEquipmentSlotItem(slotIndex));
        if (itemId === platinumCoinId || itemId === crystalCoinId) return true;
      }

      for (const container of containers) {
        for (let slotIndex = 0; slotIndex < container.slots.length; slotIndex += 1) {
          if (isSameSlot(slot, "container", container, slotIndex)) continue;
          const itemId = getItemId(container.getSlotItem(slotIndex));
          if (itemId === platinumCoinId || itemId === crystalCoinId) return true;
        }
      }

      return false;
    };
    const getValueSlotInfo = () => {
      const containers = getContainers();
      const backpackItem = getEquipmentSlotItem(getBackpackEquipmentSlotIndex());
      const backpackItemId = getItemId(backpackItem);
      const fallbackBackpackContainer = containers.find((entry) => getItemId(entry) === backpackItemId)
        || containers[0]
        || null;
      const getPreferredValueSlotInfo = () => {
        if (preferredValueSlotKind === "equipment" && Number.isInteger(preferredValueSlotIndex) && preferredValueSlotIndex >= 0) {
          return createEquipmentSlotInfo(preferredValueSlotIndex);
        }

        if (preferredValueSlotKind === "container" && Number.isInteger(preferredValueSlotIndex) && preferredValueSlotIndex >= 0) {
          const container = containers.find((entry) => Number(entry?.__containerId) === preferredValueContainerRuntimeId)
            || fallbackBackpackContainer;
          return createContainerSlotInfo(container, preferredValueSlotIndex);
        }

        return null;
      };
      const findEquipmentMarkedValueSlotInfo = () => {
        const equipmentSlots = Array.isArray(game?.player?.equipment?.slots) ? game.player.equipment.slots : [];
        for (let slotIndex = 0; slotIndex < equipmentSlots.length; slotIndex += 1) {
          const slot = createEquipmentSlotInfo(slotIndex);
          if (slotHasValueMarker(slot)) return slot;
        }

        return null;
      };
      const preferredSlot = getPreferredValueSlotInfo();
      const preferredEquipmentValueSlot = preferredSlot?.kind === "equipment"
        ? preferredSlot
        : null;
      const detectedEquipmentValueSlot = createEquipmentSlotInfo(getCurrencyPlaceholderSlotIndex());
      const markedEquipmentValueSlot = findEquipmentMarkedValueSlotInfo();
      const canonicalEquipmentValueSlot = (
        slotHasValueSignature(preferredEquipmentValueSlot)
          ? preferredEquipmentValueSlot
          : slotHasValueSignature(detectedEquipmentValueSlot)
            ? detectedEquipmentValueSlot
            : markedEquipmentValueSlot || detectedEquipmentValueSlot || preferredEquipmentValueSlot
      );
      const findStableValueCoinSlotInfo = () => {
        let best = null;
        best = preferValueCoinSlot(best, preferredEquipmentValueSlot);
        best = preferValueCoinSlot(best, detectedEquipmentValueSlot);
        best = preferValueCoinSlot(best, markedEquipmentValueSlot);
        return best;
      };
      const stableValueCoinSlot = findStableValueCoinSlotInfo();
      const shouldHoldCanonicalEmptyValueSlot = Boolean(
        canonicalEquipmentValueSlot
        && !canonicalEquipmentValueSlot.item
        && hasValueCoinsOutsideSlot(canonicalEquipmentValueSlot, containers)
      );
      const explicitValueSlot = (
        slotHasValueSignature(canonicalEquipmentValueSlot) || shouldHoldCanonicalEmptyValueSlot
          ? canonicalEquipmentValueSlot
          : null
      );
      if (explicitValueSlot) return explicitValueSlot;

      return stableValueCoinSlot || canonicalEquipmentValueSlot || preferredSlot || null;
    };
    const describePinnedValueSlot = (valueSlot) => (
      valueSlot
        ? {
            kind: valueSlot.kind,
            slotIndex: valueSlot.slotIndex,
            containerRuntimeId: valueSlot.kind === "container"
              ? (Number(valueSlot.container?.__containerId) || null)
              : null,
          }
        : null
    );
    const resolvePinnedValueSlotInfo = (pinnedValueSlot, containers = getContainers()) => {
      if (!pinnedValueSlot || !Number.isInteger(pinnedValueSlot.slotIndex) || pinnedValueSlot.slotIndex < 0) {
        return null;
      }

      if (pinnedValueSlot.kind === "equipment") {
        return createEquipmentSlotInfo(pinnedValueSlot.slotIndex);
      }

      if (pinnedValueSlot.kind === "container") {
        const container = containers.find((entry) => Number(entry?.__containerId) === Number(pinnedValueSlot.containerRuntimeId))
          || (containers.length === 1 ? containers[0] : null);
        return createContainerSlotInfo(container, pinnedValueSlot.slotIndex);
      }

      return null;
    };
    const getStrayCurrencySlotInfo = (valueSlot = getValueSlotInfo()) => {
      const equipment = game?.player?.equipment;
      const slotIndex = getCurrencyPlaceholderSlotIndex();
      if (valueSlot?.kind === "equipment" && valueSlot.slotIndex === slotIndex) {
        return null;
      }
      const item = equipment && typeof equipment.getSlotItem === "function"
        ? equipment.getSlotItem(slotIndex)
        : null;
      return {
        kind: "equipment",
        which: equipment,
        equipment,
        slotIndex,
        item,
        itemId: getItemId(item),
        count: getItemCount(item),
      };
    };
    const findFullPlatinumPlaceholderStack = () => {
      if (!includePlatinumPlaceholder) return null;

      const info = getValueSlotInfo();
      if (!info?.which) return null;
      if (!info.item || info.itemId !== platinumCoinId || info.count !== 100) return null;
      return { which: info.which, index: info.slotIndex };
    };
    const findEmptyContainerSlot = (containers = []) => {
      const primaryBackpackContainer = getPrimaryBackpackContainer(containers);
      const orderedContainers = primaryBackpackContainer
        ? [primaryBackpackContainer, ...containers.filter((container) => container !== primaryBackpackContainer)]
        : containers;
      for (const container of orderedContainers) {
        if (!container || !Array.isArray(container.slots) || typeof container.getSlotItem !== "function") continue;

        for (let index = 0; index < container.slots.length; index += 1) {
          if (!container.getSlotItem(index)) {
            return { which: container, index };
          }
        }
      }

      return null;
    };
    const findRelocationContainerSlot = (itemId, itemCount, containers = [], exclude = null) => {
      if (itemId == null || !Number.isFinite(Number(itemCount)) || Number(itemCount) <= 0) {
        return null;
      }

      const primaryBackpackContainer = getPrimaryBackpackContainer(containers);
      const orderedContainers = primaryBackpackContainer
        ? [primaryBackpackContainer, ...containers.filter((container) => container !== primaryBackpackContainer)]
        : containers;
      const mergeTargets = [];

      for (const container of orderedContainers) {
        if (!container || !Array.isArray(container.slots) || typeof container.getSlotItem !== "function") continue;

        for (let index = 0; index < container.slots.length; index += 1) {
          if (exclude && container === exclude.which && index === exclude.index) continue;
          const item = container.getSlotItem(index);
          if (!item || getItemId(item) !== itemId) continue;

          const targetCount = getItemCount(item);
          if (targetCount <= 0 || targetCount >= 100) continue;
          const isKnownStackableCurrency = itemId === goldCoinId || itemId === platinumCoinId || itemId === crystalCoinId;
          // Only merge when the item is known stackable, or when one side
          // already proves stackability by holding more than a single item.
          if (!isKnownStackableCurrency && Math.max(0, Number(itemCount) || 0) <= 1 && targetCount <= 1) continue;

          mergeTargets.push({
            which: container,
            index,
            count: targetCount,
          });
        }
      }

      const sortMergeTargets = (left, right) => (
        (left.which === primaryBackpackContainer ? -1 : 0) - (right.which === primaryBackpackContainer ? -1 : 0)
        || right.count - left.count
        || left.index - right.index
      );
      const fullAcceptTarget = mergeTargets
        .filter((candidate) => candidate.count + itemCount <= 100)
        .sort(sortMergeTargets)[0];
      if (fullAcceptTarget) {
        return { which: fullAcceptTarget.which, index: fullAcceptTarget.index };
      }

      const partialTarget = mergeTargets.slice().sort(sortMergeTargets)[0];
      if (partialTarget) {
        return { which: partialTarget.which, index: partialTarget.index };
      }

      return findEmptyContainerSlot(orderedContainers);
    };
    const hasCoinInContainers = (coinId, containers = []) => (
      containers.some((container) => (
        Array.from({ length: container.slots.length }).some((_, index) => getItemId(container.getSlotItem(index)) === coinId)
      ))
    );
    // Stackable coin merges are more reliable when the client receives a
    // full-source drag onto an occupied stack and leaves the overflow behind.
    const getCoinMergeRequestCount = (destinationCount, sourceCount, movedCount) => (
      destinationCount > 0 ? sourceCount : movedCount
    );
    const findCoinPlaceholderStackMoves = (requestedCoinId = null, pinnedValueSlot = null) => {
      const containers = getContainers();
      const primaryBackpackContainer = getPrimaryBackpackContainer(containers);
      const valueSlot = resolvePinnedValueSlotInfo(pinnedValueSlot, containers) || getValueSlotInfo();
      if (!valueSlot?.which || valueSlot.slotIndex < 0) return null;
      const strayCurrencySlot = getStrayCurrencySlotInfo(valueSlot);
      const hasCrystalAnywhere = (valueSlot.itemId === crystalCoinId && valueSlot.count > 0)
        || (strayCurrencySlot?.itemId === crystalCoinId && strayCurrencySlot.count > 0)
        || hasCoinInContainers(crystalCoinId, containers);

      let targetCoinId = Number(requestedCoinId);
      if (targetCoinId !== platinumCoinId && targetCoinId !== crystalCoinId) {
        if (valueSlot.item && !valueSlot.hasValueMarker) {
          if (valueSlot.itemId === crystalCoinId && valueSlot.count < 100) {
            targetCoinId = crystalCoinId;
          } else if (valueSlot.itemId === platinumCoinId && valueSlot.count < 100) {
            targetCoinId = platinumCoinId;
          } else {
            return null;
          }
        } else {
          if (hasCrystalAnywhere) {
            targetCoinId = crystalCoinId;
          } else {
            const hasPlatinum = (strayCurrencySlot?.itemId === platinumCoinId && strayCurrencySlot.count > 0)
              || hasCoinInContainers(platinumCoinId, containers);
            if (!hasPlatinum) return null;
            targetCoinId = platinumCoinId;
          }
        }
      }

      if (targetCoinId !== platinumCoinId && targetCoinId !== crystalCoinId) return null;
      if (targetCoinId === platinumCoinId && hasCrystalAnywhere) return null;

      const preparationMoves = [];
      if (valueSlot.item && !valueSlot.hasValueMarker && valueSlot.itemId !== targetCoinId) {
        const relocationSlot = findRelocationContainerSlot(
          valueSlot.itemId,
          valueSlot.count,
          containers,
          valueSlot.kind === "container"
            ? { which: valueSlot.container, index: valueSlot.slotIndex }
            : null,
        );
        if (!relocationSlot) return null;

        preparationMoves.push({
          from: { which: valueSlot.which, index: valueSlot.slotIndex },
          to: relocationSlot,
          count: Math.max(1, valueSlot.count),
          sourceCount: valueSlot.count,
          itemId: valueSlot.itemId,
          kind: "relocate-value-slot-item",
        });
      }

      const targetIsAvailable = !valueSlot.item
        || valueSlot.hasValueMarker
        || valueSlot.itemId === targetCoinId;
      if (!targetIsAvailable && preparationMoves.length <= 0) return null;

      if (valueSlot.hasValueMarker) {
        const relocationSlot = findRelocationContainerSlot(
          valueSlot.itemId,
          valueSlot.count,
          containers,
          valueSlot.kind === "container"
            ? { which: valueSlot.container, index: valueSlot.slotIndex }
            : null,
        );
        if (!relocationSlot) return null;

        preparationMoves.push({
          from: { which: valueSlot.which, index: valueSlot.slotIndex },
          to: relocationSlot,
          count: Math.max(1, valueSlot.count),
          sourceCount: valueSlot.count,
          itemId: valueSlot.itemId,
          kind: "relocate-value-slot-item",
        });
      }

      const targetCount = valueSlot.item && !valueSlot.hasValueMarker && valueSlot.itemId === targetCoinId ? valueSlot.count : 0;
      if (targetCount >= 100) return null;

      const sources = [];
      if (strayCurrencySlot?.equipment && strayCurrencySlot.itemId === targetCoinId && strayCurrencySlot.count > 0) {
        sources.push({
          from: { which: strayCurrencySlot.equipment, index: strayCurrencySlot.slotIndex },
          sourceCount: strayCurrencySlot.count,
        });
      }

      for (const container of containers) {
        if (!container || !Array.isArray(container.slots) || typeof container.getSlotItem !== "function") continue;

        for (let index = 0; index < container.slots.length; index += 1) {
          if (valueSlot.kind === "container" && container === valueSlot.container && index === valueSlot.slotIndex) continue;
          const item = container.getSlotItem(index);
          if (!item || getItemId(item) !== targetCoinId) continue;
          sources.push({
            from: { which: container, index },
            sourceCount: getItemCount(item),
          });
        }
      }

      const getSourcePriority = (source) => {
        if (valueSlot.kind === "equipment" && primaryBackpackContainer && source?.from?.which === primaryBackpackContainer) {
          return 0;
        }
        if (source?.from?.which === strayCurrencySlot?.equipment) {
          return 1;
        }
        return 2;
      };
      sources.sort((left, right) => (
        getSourcePriority(left) - getSourcePriority(right)
        || right.sourceCount - left.sourceCount
        || left.from.index - right.from.index
      ));

      const moves = [];
      let remaining = 100 - targetCount;
      let pendingTargetCount = targetCount;
      for (const source of sources) {
        const movedCount = Math.min(remaining, source.sourceCount);
        if (movedCount <= 0) continue;
        const requestCount = getCoinMergeRequestCount(pendingTargetCount, source.sourceCount, movedCount);

        moves.push({
          from: source.from,
          to: { which: valueSlot.which, index: valueSlot.slotIndex },
          count: requestCount,
          sourceCount: source.sourceCount,
          itemId: targetCoinId,
        });
        remaining -= movedCount;
        pendingTargetCount = Math.min(100, pendingTargetCount + movedCount);
        if (remaining <= 0) break;
      }

      return moves.length > 0
        ? {
            coinId: targetCoinId,
            moves,
            preparationMoves,
            placeholderCount: targetCount,
            valueSlotRef: describePinnedValueSlot(valueSlot),
          }
        : null;
    };
    const findCoinOverflowStackMoves = (requestedCoinId) => {
      const targetCoinId = Number(requestedCoinId);
      if (targetCoinId !== platinumCoinId && targetCoinId !== crystalCoinId) return null;

      const containers = getContainers();
      const primaryBackpackContainer = getPrimaryBackpackContainer(containers);
      const valueSlot = getValueSlotInfo();
      if (!valueSlot?.which || valueSlot.slotIndex < 0) return null;
      const strayCurrencySlot = getStrayCurrencySlotInfo();
      const stacks = [];
      const isValueSlotEntry = (kind, owner, slotIndex) => (
        valueSlot.kind === kind
        && valueSlot.slotIndex === slotIndex
        && (
          (kind === "equipment" && valueSlot.equipment === owner)
          || (kind === "container" && valueSlot.container === owner)
        )
      );

      if (
        strayCurrencySlot?.equipment
        && strayCurrencySlot.itemId === targetCoinId
        && strayCurrencySlot.count > 0
        && !isValueSlotEntry("equipment", strayCurrencySlot.equipment, strayCurrencySlot.slotIndex)
      ) {
        stacks.push({
          which: strayCurrencySlot.equipment,
          index: strayCurrencySlot.slotIndex,
          count: strayCurrencySlot.count,
        });
      }

      for (const container of containers) {
        if (!container || !Array.isArray(container.slots) || typeof container.getSlotItem !== "function") continue;

        for (let index = 0; index < container.slots.length; index += 1) {
          if (isValueSlotEntry("container", container, index)) continue;
          const item = container.getSlotItem(index);
          if (!item || getItemId(item) !== targetCoinId) continue;
          stacks.push({
            which: container,
            index,
            count: getItemCount(item),
          });
        }
      }

      const sortTargets = (left, right) => right.count - left.count || left.index - right.index;
      const targets = stacks.filter((entry) => entry.count < 100);
      if (!targets.length) return null;

      const preferredTargets = (
        valueSlot.kind === "equipment" && primaryBackpackContainer
          ? targets.filter((entry) => entry.which === primaryBackpackContainer)
          : []
      );
      const target = (preferredTargets.length ? preferredTargets : targets)
        .slice()
        .sort(sortTargets)[0];
      const sources = stacks
        .filter((entry) => !(entry.which === target.which && entry.index === target.index))
        .sort((left, right) => left.count - right.count || left.index - right.index);

      const moves = [];
      let remaining = 100 - target.count;
      let pendingTargetCount = target.count;
      for (const source of sources) {
        const movedCount = Math.min(remaining, source.count);
        if (movedCount <= 0) continue;
        const requestCount = getCoinMergeRequestCount(pendingTargetCount, source.count, movedCount);

        moves.push({
          from: { which: source.which, index: source.index },
          to: { which: target.which, index: target.index },
          count: requestCount,
          sourceCount: source.count,
          itemId: targetCoinId,
        });
        remaining -= movedCount;
        pendingTargetCount = Math.min(100, pendingTargetCount + movedCount);
        if (remaining <= 0) break;
      }

      return moves.length > 0
        ? { coinId: targetCoinId, moves, preparationMoves: [], placeholderCount: target.count }
        : null;
    };
    const findEquipmentValueCoinStageMove = (requestedCoinId) => {
      const targetCoinId = Number(requestedCoinId);
      if (targetCoinId !== platinumCoinId && targetCoinId !== crystalCoinId) return null;

      const containers = getContainers();
      const primaryBackpackContainer = getPrimaryBackpackContainer(containers);
      const valueSlot = getValueSlotInfo();
      if (!primaryBackpackContainer || valueSlot?.kind !== "equipment" || !valueSlot.which) return null;
      if (valueSlot.hasValueMarker || valueSlot.itemId !== targetCoinId || valueSlot.count <= 0) return null;

      const strayCurrencySlot = getStrayCurrencySlotInfo(valueSlot);
      const hasOutsideCoin = (
        strayCurrencySlot?.itemId === targetCoinId
        && strayCurrencySlot.count > 0
      ) || hasCoinInContainers(targetCoinId, containers);
      if (!hasOutsideCoin) return null;

      const stageCandidates = [];
      for (const container of containers) {
        for (let index = 0; index < container.slots.length; index += 1) {
          const item = container.getSlotItem(index);
          if (getItemId(item) !== targetCoinId) continue;
          const count = getItemCount(item);
          if (count <= 0 || count >= 100) continue;
          stageCandidates.push({
            which: container,
            index,
            count,
          });
        }
      }

      const sortStageCandidates = (left, right) => (
        (left.which === primaryBackpackContainer ? -1 : 0) - (right.which === primaryBackpackContainer ? -1 : 0)
        || right.count - left.count
        || left.index - right.index
      );

      let stageTarget = null;
      const fullAcceptTarget = stageCandidates
        .filter((candidate) => candidate.count + valueSlot.count <= 100)
        .sort(sortStageCandidates)[0];
      if (fullAcceptTarget) {
        stageTarget = {
          to: { which: fullAcceptTarget.which, index: fullAcceptTarget.index },
          targetCount: fullAcceptTarget.count,
        };
      }

      if (!stageTarget) {
        for (let index = 0; index < primaryBackpackContainer.slots.length; index += 1) {
          const item = primaryBackpackContainer.getSlotItem(index);
          if (getItemId(item) !== targetCoinId) continue;
          const count = getItemCount(item);
          if (count <= 0 || count >= 100) continue;

          if (!stageTarget || count > stageTarget.targetCount || (count === stageTarget.targetCount && index < stageTarget.to.index)) {
            stageTarget = {
              to: { which: primaryBackpackContainer, index },
              targetCount: count,
            };
          }
        }
      }

      if (!stageTarget) {
        const emptySlot = findEmptyContainerSlot(containers);
        if (!emptySlot) return null;
        stageTarget = {
          to: emptySlot,
          targetCount: 0,
        };
      }

      return {
        coinId: targetCoinId,
        moves: [
          {
            from: { which: valueSlot.which, index: valueSlot.slotIndex },
            to: stageTarget.to,
            count: valueSlot.count,
            sourceCount: valueSlot.count,
            itemId: targetCoinId,
            kind: "stage-equipment-value-coin",
          },
        ],
        preparationMoves: [],
        placeholderCount: stageTarget.targetCount,
      };
    };
    const sendInventoryMoves = async (moves = []) => {
      if (!moves.length) return;

      interruptAutoWalkForInventory();

      if (typeof game?.mouse?.sendItemMove === "function") {
        for (let moveIndex = 0; moveIndex < moves.length; moveIndex += 1) {
          const move = moves[moveIndex];
          game.mouse.sendItemMove(move.from, move.to, move.count);
          if (moveIndex < moves.length - 1) {
            await sleep(
              move.kind === "relocate-value-slot-item" || move.kind === "stage-equipment-value-coin"
                ? 320
                : 140,
            );
          }
        }
        return;
      }

      if (typeof game?.send === "function" && typeof ItemMovePacketCtor === "function") {
        for (const move of moves) {
          game.send(new ItemMovePacketCtor(move.from, move.to, move.count));
        }
        return;
      }

      throw new Error("inventory transport unavailable");
    };
    const stageCoinOutOfEquipmentValueSlot = async (requestedCoinId) => {
      const plan = findEquipmentValueCoinStageMove(requestedCoinId);
      const stageMoves = Array.isArray(plan?.moves) ? plan.moves : [];
      if (!stageMoves.length) return null;

      await sendInventoryMoves(stageMoves);
      await sleep(180);

      return {
        coinId: plan.coinId,
        moves: stageMoves,
        preparationMoves: [],
        count: stageMoves.reduce((sum, move) => sum + move.count, 0),
        placeholderCount: plan.placeholderCount,
        sourceCount: stageMoves.reduce((sum, move) => sum + move.sourceCount, 0),
      };
    };
    const stackCoinIntoPlaceholder = async (requestedCoinId = null) => {

      let plan = findCoinPlaceholderStackMoves(requestedCoinId);
      if (!plan) return null;

      const preparationMoves = [];
      let preparationPasses = 0;
      while (Array.isArray(plan.preparationMoves) && plan.preparationMoves.length > 0) {
        await sendInventoryMoves(plan.preparationMoves);
        preparationMoves.push(...plan.preparationMoves);
        preparationPasses += 1;
        if (preparationPasses >= 3) return null;
        await sleep(180);

        plan = findCoinPlaceholderStackMoves(plan.coinId ?? requestedCoinId, plan.valueSlotRef);
        if (!plan) {
          return preparationMoves.length > 0
            ? {
                coinId: requestedCoinId ?? null,
                moves: [],
                preparationMoves,
                count: 0,
                placeholderCount: null,
                sourceCount: 0,
              }
            : null;
        }
      }

      const coinMoves = Array.isArray(plan.moves) ? plan.moves : [];
      if (!coinMoves.length && preparationMoves.length <= 0) return null;
      if (coinMoves.length) {
        await sendInventoryMoves(coinMoves);
      }

      return {
        coinId: plan.coinId,
        moves: coinMoves,
        preparationMoves,
        count: coinMoves.reduce((sum, move) => sum + move.count, 0),
        placeholderCount: plan.placeholderCount,
        sourceCount: coinMoves.reduce((sum, move) => sum + move.sourceCount, 0),
      };
    };
    const stackCoinOutsideValueSlot = async (requestedCoinId) => {
      const plan = findCoinOverflowStackMoves(requestedCoinId);
      if (!plan) return null;
      const coinMoves = Array.isArray(plan.moves) ? plan.moves : [];
      if (!coinMoves.length) return null;

      await sendInventoryMoves(coinMoves);

      return {
        coinId: plan.coinId,
        moves: coinMoves,
        preparationMoves: [],
        count: coinMoves.reduce((sum, move) => sum + move.count, 0),
        placeholderCount: plan.placeholderCount,
        sourceCount: coinMoves.reduce((sum, move) => sum + move.sourceCount, 0),
      };
    };
    const combineStackMoves = (stackMoves = []) => {
      const settledMoves = stackMoves.filter(Boolean);
      if (!settledMoves.length) return null;
      if (settledMoves.length === 1) return settledMoves[0];

      const coinIds = [];
      for (const move of settledMoves) {
        const ids = Array.isArray(move.coinIds)
          ? move.coinIds
          : [move.coinId];
        for (const coinId of ids) {
          if (coinId == null || coinIds.includes(coinId)) continue;
          coinIds.push(coinId);
        }
      }

      const placeholderMove = [...settledMoves].reverse().find((move) => move.placeholderCount != null) || null;

      return {
        coinId: coinIds.length === 1 ? coinIds[0] : null,
        coinIds,
        moves: settledMoves.flatMap((move) => Array.isArray(move.moves) ? move.moves : []),
        preparationMoves: settledMoves.flatMap((move) => Array.isArray(move.preparationMoves) ? move.preparationMoves : []),
        count: settledMoves.reduce((sum, move) => sum + (Number(move.count) || 0), 0),
        placeholderCount: placeholderMove?.placeholderCount ?? null,
        sourceCount: settledMoves.reduce((sum, move) => sum + (Number(move.sourceCount) || 0), 0),
      };
    };
    const serializeStackMove = (move) => (
      move
        ? {
            coinId: move.coinId ?? null,
            coinIds: Array.isArray(move.coinIds)
              ? move.coinIds
              : (move.coinId != null ? [move.coinId] : []),
            count: move.count,
            placeholderCount: move.placeholderCount,
            sourceCount: move.sourceCount,
            moveCount: Array.isArray(move.moves) ? move.moves.length : 0,
            preparationMoveCount: Array.isArray(move.preparationMoves) ? move.preparationMoves.length : 0,
            fromIndex: move.moves?.[0]?.from.index ?? null,
            fromIndices: Array.isArray(move.moves) ? move.moves.map((entry) => entry.from.index) : [],
            toIndex: move.moves?.[0]?.to.index ?? null,
          }
        : null
    );
    const routePlaceholderCoins = async () => {
      const routeCoin = async (coinId) => {
        const placeholderMove = await stackCoinIntoPlaceholder(coinId);
        if (placeholderMove) return placeholderMove;
        return stackCoinOutsideValueSlot(coinId);
      };

      const stackMoves = [];
      const crystalMove = await routeCoin(crystalCoinId);
      if (crystalMove) stackMoves.push(crystalMove);
      const platinumMove = await routeCoin(platinumCoinId);
      if (platinumMove) stackMoves.push(platinumMove);
      return combineStackMoves(stackMoves);
    };
    const findFullStack = (coinId) => hotbar.__findFullCoinStack(coinId);
    const isValueSlotTarget = (valueSlot, found) => Boolean(
      valueSlot
      && found
      && valueSlot.which === found.which
      && valueSlot.slotIndex === found.index
    );
    const findConvertibleStack = () => {
      const valueSlot = getValueSlotInfo();
      const fullPlatinumPlaceholderStack = findFullPlatinumPlaceholderStack();
      for (const coinId of coinIds) {
        const found = coinId === platinumCoinId && fullPlatinumPlaceholderStack
          ? fullPlatinumPlaceholderStack
          : findFullStack(coinId);
        if (coinId === platinumCoinId && isValueSlotTarget(valueSlot, found) && !includePlatinumPlaceholder) continue;
        if (found) return { coinId, found };
      }
      return null;
    };
    const hasGold = () => Boolean(findFullStack(goldCoinId));
    const hasPlatinum = () => Boolean(findFullStack(platinumCoinId));
    const hadGold = hasGold();
    const hadPlatinum = hasPlatinum();
    const canConvert = () => Boolean(findConvertibleStack());

    if (!canConvert()) {
      if (routeCurrencyPlaceholder && allowStandaloneValueSlotRouting) {
        const stackMove = await routePlaceholderCoins();
        if (stackMove) {
          return {
            ok: true,
            attempts: 0,
            stacked: true,
            stackMove: serializeStackMove(stackMove),
            hadGold,
            hadPlatinum,
            hasGold: hasGold(),
            hasPlatinum: hasPlatinum(),
          };
        }
      }

      return { ok: false, reason: "no full coin stack" };
    }

    let attempts = 0;
    const convertedCoinIds = [];
    while (attempts < maxAttempts && canConvert()) {
      const target = findConvertibleStack();
      if (!target) break;

      const isPlaceholderTarget = target.coinId === platinumCoinId && target.found?.which === game?.player?.equipment;
      interruptAutoWalkForInventory();

      if (isPlaceholderTarget && typeof game?.mouse?.use === "function") {
        game.mouse.use(target.found);
      } else if (typeof game?.send === "function" && typeof ItemUsePacketCtor === "function") {
        game.send(new ItemUsePacketCtor(target.found));
      } else if (!isPlaceholderTarget) {
        hotbar.__convertCurrency();
      } else {
        break;
      }

      convertedCoinIds.push(target.coinId);
      attempts += 1;
    }

    const stackMove = routeCurrencyPlaceholder && attempts > 0
      ? await routePlaceholderCoins()
      : null;

    return {
      ok: attempts > 0 || Boolean(stackMove),
      attempts,
      convertedCoinIds,
      stacked: Boolean(stackMove),
      stackMove: serializeStackMove(stackMove),
      hadGold,
      hadPlatinum,
      hasGold: hasGold(),
      hasPlatinum: hasPlatinum(),
    };
  })()`;
}

function buildUseToolOnPositionExpression(toolIds = [], targetPosition = {}) {
  const ids = Array.isArray(toolIds)
    ? toolIds.map((value) => Math.trunc(Number(value))).filter((value) => Number.isInteger(value) && value > 0)
    : [];
  const x = Number(targetPosition.x);
  const y = Number(targetPosition.y);
  const z = Number(targetPosition.z);

  return `(() => {
    const toolIds = ${JSON.stringify(ids)};
    const game = window.gameClient;
    const world = game?.world;
    const PositionCtor = globalThis.Position || game?.player?.__position?.constructor;
    const fallbackPos = { x: ${Number.isFinite(x) ? Math.trunc(x) : 0}, y: ${Number.isFinite(y) ? Math.trunc(y) : 0}, z: ${Number.isFinite(z) ? Math.trunc(z) : 0} };
    const position = typeof PositionCtor === "function"
      ? new PositionCtor(fallbackPos.x, fallbackPos.y, fallbackPos.z)
      : fallbackPos;

    if (!game || !world || !toolIds.length) {
      return { ok: false, reason: "tool unavailable" };
    }

    const tile = (
      [
        typeof world.getTile === "function" ? world.getTile(position) : null,
        typeof world.map?.getTile === "function" ? world.map.getTile(position) : null,
        typeof game.map?.getTile === "function" ? game.map.getTile(position) : null,
      ].find(Boolean)
    ) || null;

    const topThing = tile?.getTopUseThing?.()
      || tile?.getTopThing?.()
      || tile?.getTopLookThing?.()
      || (Array.isArray(tile?.things) && tile.things.length ? tile.things[tile.things.length - 1] : null);

    const callers = [
      window.g_game,
      globalThis.g_game,
      game,
      game.game,
      world,
    ].filter(Boolean);

    for (const itemId of toolIds) {
      for (const caller of callers) {
        if (topThing && typeof caller.useInventoryItemWith === "function") {
          caller.useInventoryItemWith(itemId, topThing);
          return { ok: true, itemId, mode: "useInventoryItemWith" };
        }

        if (tile && typeof caller.useWith === "function") {
          caller.useWith(itemId, tile);
          return { ok: true, itemId, mode: "useWith" };
        }

        if (typeof caller.useMapItem === "function") {
          caller.useMapItem(position);
          return { ok: true, itemId, mode: "useMapItem" };
        }
      }
    }

    return {
      ok: false,
      reason: topThing || tile ? "tool call unavailable" : "tile unavailable",
      hasTile: Boolean(tile),
      hasTopThing: Boolean(topThing),
    };
  })()`;
}

function buildUseMapItemExpression(targetPosition = {}) {
  const x = Number(targetPosition.x);
  const y = Number(targetPosition.y);
  const z = Number(targetPosition.z);

  return `(() => {
    const game = window.gameClient;
    const world = game?.world;
    const PositionCtor = globalThis.Position || game?.player?.__position?.constructor;
    const fallbackPos = { x: ${Number.isFinite(x) ? Math.trunc(x) : 0}, y: ${Number.isFinite(y) ? Math.trunc(y) : 0}, z: ${Number.isFinite(z) ? Math.trunc(z) : 0} };
    const position = typeof PositionCtor === "function"
      ? new PositionCtor(fallbackPos.x, fallbackPos.y, fallbackPos.z)
      : fallbackPos;

    if (!game || !world) {
      return { ok: false, reason: "use unavailable" };
    }

    const tile = (
      [
        typeof world.getTile === "function" ? world.getTile(position) : null,
        typeof world.map?.getTile === "function" ? world.map.getTile(position) : null,
        typeof game.map?.getTile === "function" ? game.map.getTile(position) : null,
      ].find(Boolean)
    ) || null;

    const topThing = tile?.getTopUseThing?.()
      || tile?.getTopThing?.()
      || tile?.getTopLookThing?.()
      || (Array.isArray(tile?.things) && tile.things.length ? tile.things[tile.things.length - 1] : null);

    const callers = [
      window.g_game,
      globalThis.g_game,
      game,
      game.game,
      world,
    ].filter(Boolean);

    for (const caller of callers) {
      if (topThing && typeof caller.use === "function") {
        caller.use(topThing);
        return { ok: true, mode: "useThing" };
      }

      if (tile && typeof caller.use === "function") {
        caller.use(tile);
        return { ok: true, mode: "useTile" };
      }

      if (typeof caller.useMapItem === "function") {
        caller.useMapItem(position);
        return { ok: true, mode: "useMapItem" };
      }
    }

    if (topThing && typeof topThing.use === "function") {
      topThing.use();
      return { ok: true, mode: "thing.use" };
    }

    return {
      ok: false,
      reason: topThing || tile ? "use call unavailable" : "tile unavailable",
      hasTile: Boolean(tile),
      hasTopThing: Boolean(topThing),
    };
  })()`;
}

function buildAntiIdleExpression() {
  return `(async () => {
    const game = window.gameClient;
    const doc = window.document || globalThis.document || null;
    const networkManager = game?.networkManager;
    const installBackgroundActivityGuard = () => {
      const guardVersion = 1;
      const guardKey = "__minibotBackgroundActivityGuard";

      if (!doc || window[guardKey]?.version === guardVersion) {
        return window[guardKey] || null;
      }

      const defineConstantGetter = (target, key, value) => {
        if (!target) return false;

        try {
          const descriptor = Object.getOwnPropertyDescriptor(target, key);
          if (descriptor && descriptor.configurable === false) {
            return false;
          }

          Object.defineProperty(target, key, {
            configurable: true,
            enumerable: descriptor?.enumerable ?? true,
            get: () => value,
          });
          return true;
        } catch {
          return false;
        }
      };

      const blockVisibilityDowngrade = (event) => {
        try {
          event?.stopImmediatePropagation?.();
          event?.stopPropagation?.();
        } catch {}
      };

      defineConstantGetter(doc, "hidden", false);
      defineConstantGetter(doc, "visibilityState", "visible");
      defineConstantGetter(doc, "webkitHidden", false);
      defineConstantGetter(doc, "webkitVisibilityState", "visible");

      try {
        doc.hasFocus = () => true;
      } catch {}

      try {
        window.addEventListener("blur", blockVisibilityDowngrade, true);
        window.addEventListener("visibilitychange", blockVisibilityDowngrade, true);
        doc.addEventListener?.("visibilitychange", blockVisibilityDowngrade, true);
      } catch {}

      window[guardKey] = {
        version: guardVersion,
        installedAt: Date.now(),
      };
      return window[guardKey];
    };

    const awaitMaybe = async (value) => {
      if (!value || typeof value.then !== "function") {
        return value;
      }

      return Promise.race([
        value,
        new Promise((_, reject) => setTimeout(() => reject(new Error("keepalive hook timed out")), 650)),
      ]);
    };

    const methodNames = [
      "sendKeepAlive",
      "sendKeepalive",
      "keepAlive",
      "sendHeartbeat",
      "heartbeat",
      "sendPing",
      "ping",
    ];
    const targets = [
      { label: "networkManager", value: networkManager },
      { label: "networkManager.connection", value: networkManager?.connection },
      { label: "networkManager.protocol", value: networkManager?.protocol },
      { label: "gameClient", value: game },
      { label: "g_game", value: window.g_game || globalThis.g_game },
    ];
    let lastError = "";

    installBackgroundActivityGuard();
    try {
      window.focus?.();
      doc?.body?.focus?.();
    } catch {}

    for (const target of targets) {
      if (!target.value) continue;

      for (const methodName of methodNames) {
        const method = target.value?.[methodName];
        if (typeof method !== "function") continue;

        try {
          await awaitMaybe(method.call(target.value));
          return {
            ok: true,
            transport: "game-keepalive",
            method: String(target.label || "") + "." + String(methodName || ""),
          };
        } catch (error) {
          lastError = error?.message || String(error || "");
        }
      }
    }

    return {
      ok: false,
      reason: "keepalive unavailable",
      message: lastError || "",
    };
  })()`;
}

function buildClearWaypointOverlayExpression() {
  return `(() => {
    const root = document.getElementById("${WAYPOINT_OVERLAY_ROOT_ID}");
    const state = root?.__mbtState;
    if (state?.frame != null && typeof window.cancelAnimationFrame === "function") {
      window.cancelAnimationFrame(state.frame);
    }
    if (typeof state?.resizeObserver?.disconnect === "function") {
      state.resizeObserver.disconnect();
    }
    if (typeof state?.removeResizeListener === "function") {
      state.removeResizeListener();
    }
    if (typeof state?.removeViewportResizeListener === "function") {
      state.removeViewportResizeListener();
    }
    if (typeof state?.removeViewportScrollListener === "function") {
      state.removeViewportScrollListener();
    }
    if (state) {
      state.running = false;
      state.frame = null;
      state.resizeObserver = null;
      state.observedWrapper = null;
      state.observedScreen = null;
    }
    root?.remove();
    document.getElementById("${WAYPOINT_OVERLAY_STYLE_ID}")?.remove();
    return { ok: true };
  })()`;
}

function buildWaypointOverlayExpression({
  waypoints,
  tileRules,
  routeIndex,
  focusIndex,
  autowalkLoop,
  routeTelemetry = null,
  showWaypointOverlay,
  suppressRouteHighlights = false,
}) {
  const normalizedWaypoints = Array.isArray(waypoints) ? waypoints.map(normalizeWaypoint).filter(Boolean) : [];
  const normalizedTileRules = Array.isArray(tileRules) ? tileRules.map(normalizeTileRule).filter(Boolean) : [];
  const payload = {
    waypoints: normalizedWaypoints.map((waypoint, index) => {
      return {
        x: waypoint.x,
        y: waypoint.y,
        z: waypoint.z,
        label: String(waypoint.label || "").trim(),
        tinyLabel: formatWaypointOverlayTinyLabel(waypoint, index),
        type: waypoint.type,
        action: waypoint.type === "action" ? normalizeWaypointAction(waypoint.action) : null,
        targetIndex: normalizeWaypointTargetIndex(waypoint.targetIndex),
        order: index + 1,
      };
    }),
    tileRules: normalizedTileRules.map((rule, index) => ({
      x: rule.x,
      y: rule.y,
      z: rule.z,
      width: rule.width,
      height: rule.height,
      shape: rule.shape,
      policy: rule.policy,
      order: index + 1,
    })),
    routeIndex: Number.isFinite(Number(routeIndex)) ? Math.trunc(Number(routeIndex)) : 0,
    focusIndex: Number.isFinite(Number(focusIndex)) ? Math.trunc(Number(focusIndex)) : null,
    autowalkLoop: Boolean(autowalkLoop),
    routeTelemetry: {
      lapCount: Math.max(0, Math.trunc(Number(routeTelemetry?.lapCount) || 0)),
      killCount: Math.max(0, Math.trunc(Number(routeTelemetry?.killCount) || 0)),
      lootGoldValue: Math.max(0, Math.trunc(Number(routeTelemetry?.lootGoldValue) || 0)),
      lootLine: String(routeTelemetry?.lootLine || "").trim(),
      stuck: Boolean(routeTelemetry?.stuck),
      stuckWaypointIndex: Number.isFinite(Number(routeTelemetry?.stuckWaypointIndex))
        ? Math.max(0, Math.trunc(Number(routeTelemetry.stuckWaypointIndex)))
        : null,
      stuckReason: String(routeTelemetry?.stuckReason || "").trim().toLowerCase(),
    },
    showWaypointOverlay: Boolean(showWaypointOverlay),
    suppressRouteHighlights: Boolean(suppressRouteHighlights),
  };

  return `(() => {
    const payload = ${JSON.stringify(payload)};
    const overlayId = "${WAYPOINT_OVERLAY_ROOT_ID}";
    const styleId = "${WAYPOINT_OVERLAY_STYLE_ID}";
    const disposeOverlay = () => {
      const existingRoot = document.getElementById(overlayId);
      const existingState = existingRoot?.__mbtState;
      if (existingState?.frame != null && typeof window.cancelAnimationFrame === "function") {
        window.cancelAnimationFrame(existingState.frame);
      }
      if (typeof existingState?.resizeObserver?.disconnect === "function") {
        existingState.resizeObserver.disconnect();
      }
      if (typeof existingState?.removeResizeListener === "function") {
        existingState.removeResizeListener();
      }
      if (typeof existingState?.removeViewportResizeListener === "function") {
        existingState.removeViewportResizeListener();
      }
      if (typeof existingState?.removeViewportScrollListener === "function") {
        existingState.removeViewportScrollListener();
      }
      if (existingState) {
        existingState.running = false;
        existingState.frame = null;
        existingState.resizeObserver = null;
        existingState.observedWrapper = null;
        existingState.observedScreen = null;
      }
      existingRoot?.remove();
      document.getElementById(styleId)?.remove();
    };
    if (!payload.showWaypointOverlay) {
      disposeOverlay();
      return { ok: true, visibleWaypoints: 0, hidden: true };
    }

    let style = document.getElementById(styleId);
    if (!style) {
      style = document.createElement("style");
      style.id = styleId;
      style.textContent = [
        "#" + overlayId + "{position:absolute;left:0;top:0;pointer-events:none;overflow:hidden;isolation:isolate;contain:layout paint size;}",
        "#" + overlayId + " canvas{display:block;width:100%;height:100%;}",
      ].join("");
      document.head.appendChild(style);
    }

    const resolveSurface = () => {
      const screenManager = window.gameClient?.interface?.screenElementManager;
      const screen = screenManager?.screen
        || screenManager?.screenCanvas
        || document.getElementById("screen")
        || screenManager?.screenWrapper?.querySelector?.("canvas")
        || document.querySelector("canvas#screen, #screen, #wrapper canvas, canvas");
      const wrapper = screenManager?.screenWrapper
        || screen?.parentElement
        || screen?.closest?.("#wrapper, .screen-wrapper, .game-screen, [data-screen-wrapper]")
        || document.getElementById("wrapper");
      const renderer = window.gameClient?.renderer;
      const player = window.gameClient?.player;
      const world = window.gameClient?.world;
      return {
        screen,
        wrapper,
        renderer,
        player,
        world,
      };
    };

    const initialSurface = resolveSurface();
    if (!initialSurface.screen || !initialSurface.wrapper || !initialSurface.renderer || !initialSurface.player?.__position || typeof initialSurface.renderer.getStaticScreenPosition !== "function") {
      disposeOverlay();
      return { ok: false, reason: "overlay unavailable" };
    }

    const placeOverlayRoot = (overlayRoot, wrapper, screen) => {
      if (!overlayRoot || !wrapper) return;
      const shouldSitAfterScreen = Boolean(screen && screen.parentElement === wrapper);
      if (overlayRoot.parentElement !== wrapper) {
        if (shouldSitAfterScreen) {
          wrapper.insertBefore(overlayRoot, screen.nextSibling);
        } else {
          wrapper.appendChild(overlayRoot);
        }
        return;
      }
      if (shouldSitAfterScreen && overlayRoot.previousElementSibling !== screen) {
        wrapper.insertBefore(overlayRoot, screen.nextSibling);
      }
    };

    let root = document.getElementById(overlayId);
    if (!root) {
      root = document.createElement("div");
      root.id = overlayId;
    }

    if (getComputedStyle(initialSurface.wrapper).position === "static") {
      initialSurface.wrapper.style.position = "relative";
    }
    placeOverlayRoot(root, initialSurface.wrapper, initialSurface.screen);

    let canvas = root.querySelector("canvas");
    if (!canvas) {
      canvas = document.createElement("canvas");
      root.appendChild(canvas);
    }

    const collectValues = (value) => (
      value
        ? Array.from(value.values ? value.values() : Object.values(value))
        : []
    );
    const readPosition = (entity) => entity?.__position || entity?.position || null;

    const getTypeStyle = (type, emphasized = false) => {
      switch (type) {
        case "avoid":
          return emphasized
            ? { stroke: "rgba(255,136,136,0.88)", fill: "rgba(255,136,136,0.18)", edge: "rgba(255,236,236,0.28)" }
            : { stroke: "rgba(255,136,136,0.48)", fill: "rgba(255,136,136,0.09)", edge: "rgba(255,236,236,0.14)" };
        case "action":
        case "use-item":
        case "ladder":
        case "rope":
        case "shovel-hole":
        case "exani-tera":
          return emphasized
            ? { stroke: "rgba(255,214,126,0.9)", fill: "rgba(255,214,126,0.18)", edge: "rgba(255,244,210,0.3)" }
            : { stroke: "rgba(255,214,126,0.48)", fill: "rgba(255,214,126,0.09)", edge: "rgba(255,244,210,0.14)" };
        case "stairs-up":
        case "stairs-down":
        case "exit-zone":
          return emphasized
            ? { stroke: "rgba(137,224,255,0.9)", fill: "rgba(137,224,255,0.18)", edge: "rgba(222,248,255,0.3)" }
            : { stroke: "rgba(137,224,255,0.46)", fill: "rgba(137,224,255,0.08)", edge: "rgba(222,248,255,0.14)" };
        case "safe-zone":
        case "stand":
        case "node":
        case "helper":
          return emphasized
            ? { stroke: "rgba(203,238,255,0.88)", fill: "rgba(203,238,255,0.18)", edge: "rgba(255,255,255,0.28)" }
            : { stroke: "rgba(203,238,255,0.46)", fill: "rgba(203,238,255,0.08)", edge: "rgba(255,255,255,0.12)" };
        case "walk":
        default:
          return emphasized
            ? { stroke: "rgba(136,246,184,0.88)", fill: "rgba(136,246,184,0.18)", edge: "rgba(231,255,240,0.28)" }
            : { stroke: "rgba(136,246,184,0.46)", fill: "rgba(136,246,184,0.08)", edge: "rgba(231,255,240,0.12)" };
      }
    };

    const getRuleStyle = (policy) => (
      policy === "wait"
        ? { stroke: "rgba(126,206,255,0.46)", fill: "rgba(126,206,255,0.07)" }
        : { stroke: "rgba(255,124,124,0.4)", fill: "rgba(255,124,124,0.06)" }
    );
    const getRoutePreviewColor = (rank) => {
      if (!Number.isFinite(rank) || rank < 0 || rank > 4) return "";
      const mix = rank / 4;
      const start = { r: 255, g: 226, b: 92, a: 0.96 };
      const end = { r: 233, g: 78, b: 63, a: 0.9 };
      const r = Math.round(start.r + (end.r - start.r) * mix);
      const g = Math.round(start.g + (end.g - start.g) * mix);
      const b = Math.round(start.b + (end.b - start.b) * mix);
      const a = start.a + (end.a - start.a) * mix;
      return "rgba(" + String(r) + "," + String(g) + "," + String(b) + "," + String(a.toFixed(3)) + ")";
    };
    const clampRadius = (width, height, radius) => Math.max(0, Math.min(radius, width / 2, height / 2));
    const traceRoundedRect = (context, left, top, width, height, radius) => {
      const resolvedRadius = clampRadius(width, height, radius);
      context.beginPath();
      context.moveTo(left + resolvedRadius, top);
      context.lineTo(left + width - resolvedRadius, top);
      context.quadraticCurveTo(left + width, top, left + width, top + resolvedRadius);
      context.lineTo(left + width, top + height - resolvedRadius);
      context.quadraticCurveTo(left + width, top + height, left + width - resolvedRadius, top + height);
      context.lineTo(left + resolvedRadius, top + height);
      context.quadraticCurveTo(left, top + height, left, top + height - resolvedRadius);
      context.lineTo(left, top + resolvedRadius);
      context.quadraticCurveTo(left, top, left + resolvedRadius, top);
      context.closePath();
    };
    const traceSegmentedFrame = (context, left, top, width, height, radius, segmentLength) => {
      const resolvedRadius = clampRadius(width, height, radius);
      const maxHorizontal = Math.max(3, width / 2 - resolvedRadius);
      const maxVertical = Math.max(3, height / 2 - resolvedRadius);
      const resolvedSegment = Math.max(3, Math.min(segmentLength, maxHorizontal, maxVertical));
      context.beginPath();
      context.moveTo(left + resolvedRadius + resolvedSegment, top);
      context.lineTo(left + resolvedRadius, top);
      context.quadraticCurveTo(left, top, left, top + resolvedRadius);
      context.lineTo(left, top + resolvedRadius + resolvedSegment);

      context.moveTo(left + width - resolvedRadius - resolvedSegment, top);
      context.lineTo(left + width - resolvedRadius, top);
      context.quadraticCurveTo(left + width, top, left + width, top + resolvedRadius);
      context.lineTo(left + width, top + resolvedRadius + resolvedSegment);

      context.moveTo(left + width, top + height - resolvedRadius - resolvedSegment);
      context.lineTo(left + width, top + height - resolvedRadius);
      context.quadraticCurveTo(left + width, top + height, left + width - resolvedRadius, top + height);
      context.lineTo(left + width - resolvedRadius - resolvedSegment, top + height);

      context.moveTo(left + resolvedRadius + resolvedSegment, top + height);
      context.lineTo(left + resolvedRadius, top + height);
      context.quadraticCurveTo(left, top + height, left, top + height - resolvedRadius);
      context.lineTo(left, top + height - resolvedRadius - resolvedSegment);
    };
    const clipText = (value, maxLength = 22) => {
      const trimmed = String(value || "").trim();
      if (!trimmed || trimmed.length <= maxLength) return trimmed;
      return trimmed.slice(0, Math.max(0, maxLength - 3)) + "...";
    };
    const resolveColorParts = (color) => {
      const match = String(color || "").match(/^rgba?\\(([^)]+)\\)$/i);
      if (!match) return null;
      const parts = match[1].split(",").map((part) => part.trim());
      if (parts.length < 3) return null;
      return {
        r: parts[0],
        g: parts[1],
        b: parts[2],
        a: parts.length >= 4 && Number.isFinite(Number(parts[3])) ? Math.max(0, Math.min(1, Number(parts[3]))) : 1,
      };
    };
    const multiplyColorAlpha = (color, factor = 1) => {
      const resolved = resolveColorParts(color);
      if (!resolved) return color;
      return "rgba(" + resolved.r + "," + resolved.g + "," + resolved.b + "," + String(Math.max(0, Math.min(1, resolved.a * factor)).toFixed(3)) + ")";
    };
    const boostColorAlpha = (color, delta = 0) => {
      const resolved = resolveColorParts(color);
      if (!resolved) return color;
      return "rgba(" + resolved.r + "," + resolved.g + "," + resolved.b + "," + String(Math.max(0, Math.min(1, resolved.a + delta)).toFixed(3)) + ")";
    };
    const STEP_TINT_PALETTE = {
      teal: {
        text: "rgba(244,255,252,0.988)",
        badgeFill: "rgba(112,234,208,0.15)",
        badgeStroke: "rgba(205,255,242,0.42)",
      },
      yellow: {
        text: "rgba(255,252,240,0.988)",
        badgeFill: "rgba(255,224,120,0.16)",
        badgeStroke: "rgba(255,245,194,0.44)",
      },
      white: {
        text: "rgba(255,255,255,0.992)",
        badgeFill: "rgba(255,255,255,0.11)",
        badgeStroke: "rgba(255,255,255,0.34)",
      },
    };
    const getStepTintSequence = (count = 1) => {
      const resolvedCount = Math.max(1, Math.trunc(Number(count) || 0));
      if (resolvedCount === 1) return ["white"];
      if (resolvedCount === 2) return ["teal", "yellow"];
      if (resolvedCount === 3) return ["teal", "yellow", "white"];
      if (resolvedCount === 4) return ["yellow", "teal", "teal", "yellow"];
      const cycle = ["teal", "yellow", "white", "yellow", "teal"];
      return Array.from({ length: resolvedCount }, (_, index) => cycle[index % cycle.length]);
    };
    const formatOverlayCounterLine = (telemetry, routeIndex, totalWaypoints) => {
      if (telemetry?.stuck) {
        const stuckWaypointIndex = Number.isInteger(telemetry.stuckWaypointIndex)
          ? telemetry.stuckWaypointIndex
          : routeIndex;
        return "STUCK " + String(Math.max(0, stuckWaypointIndex) + 1);
      }
      if (totalWaypoints > 0) {
        return String(Math.max(0, routeIndex) + 1) + "/" + String(totalWaypoints);
      }
      return "NO ROUTE";
    };
    const formatOverlayLootLine = (telemetry) => {
      const lootLine = String(telemetry?.lootLine || "").trim();
      return "LOOT " + (lootLine || "none");
    };
    const formatOverlayCompactNumber = (value) => {
      const normalized = Math.max(0, Math.trunc(Number(value) || 0));
      if (normalized >= 1000000) {
        const millions = normalized / 1000000;
        return String(millions >= 10 ? Math.round(millions) : Number(millions.toFixed(1))) + "m";
      }
      if (normalized >= 1000) {
        const thousands = normalized / 1000;
        return String(thousands >= 10 ? Math.round(thousands) : Number(thousands.toFixed(1))) + "k";
      }
      return String(normalized);
    };

    let state = root.__mbtState;
    if (!state) {
      state = {
        frame: null,
        running: false,
        payload,
        payloadRevision: 0,
        canvas,
        ctx: null,
        needsRedraw: true,
        resizeObserver: null,
        observedWrapper: null,
        observedScreen: null,
        removeResizeListener: null,
        removeViewportResizeListener: null,
        removeViewportScrollListener: null,
        lastFrameSignature: "",
        lastStats: { ok: true, visibleWaypoints: 0, visibleTileRules: 0, hidden: false },
      };
      root.__mbtState = state;
    }

    state.payload = payload;
    state.payloadRevision = (state.payloadRevision || 0) + 1;
    state.canvas = canvas;
    state.needsRedraw = true;
    if (state.ctx?.canvas !== canvas) {
      state.ctx = null;
    }

    if (!state.requestRedraw) {
      state.requestRedraw = () => {
        state.needsRedraw = true;
        if (typeof state.startLoop === "function") {
          state.startLoop();
        }
      };
    }

    if (!state.draw) {
      state.draw = () => {
        const surface = resolveSurface();
        const screen = surface.screen;
        const wrapper = surface.wrapper;
        const renderer = surface.renderer;
        const player = surface.player;
        const world = surface.world;

        if (!root.isConnected || !screen || !wrapper || !renderer || !player?.__position || typeof renderer.getStaticScreenPosition !== "function") {
          return { ok: false, reason: "overlay unavailable" };
        }

        if (getComputedStyle(wrapper).position === "static") {
          wrapper.style.position = "relative";
        }
        placeOverlayRoot(root, wrapper, screen);
        if (typeof state.bindObservers === "function") {
          state.bindObservers(wrapper, screen);
        }

        const wrapperRect = wrapper.getBoundingClientRect();
        const screenRect = screen.getBoundingClientRect();
        const viewportRect = wrapperRect.width > 0 && wrapperRect.height > 0
          ? wrapperRect
          : screenRect;

        root.style.left = String(viewportRect.left - wrapperRect.left) + "px";
        root.style.top = String(viewportRect.top - wrapperRect.top) + "px";
        root.style.width = String(viewportRect.width) + "px";
        root.style.height = String(viewportRect.height) + "px";

        const cssWidth = Math.max(0, viewportRect.width);
        const cssHeight = Math.max(0, viewportRect.height);
        const dpr = Math.max(1, Math.min(2, window.devicePixelRatio || 1));
        const pixelWidth = Math.max(1, Math.round(cssWidth * dpr));
        const pixelHeight = Math.max(1, Math.round(cssHeight * dpr));

        if (canvas.width !== pixelWidth) canvas.width = pixelWidth;
        if (canvas.height !== pixelHeight) canvas.height = pixelHeight;
        canvas.style.width = String(cssWidth) + "px";
        canvas.style.height = String(cssHeight) + "px";

        const ctx = state.ctx
          || canvas.getContext("2d", { alpha: true, desynchronized: true })
          || canvas.getContext("2d");
        if (!ctx) {
          return { ok: false, reason: "overlay canvas unavailable" };
        }
        state.ctx = ctx;

        const columns = Math.max(1, Math.round((screen.width || 0) / 32) || 15);
        const rows = Math.max(1, Math.round((screen.height || 0) / 32) || 11);
        const tileWidth = columns > 0 ? cssWidth / columns : cssWidth;
        const tileHeight = rows > 0 ? cssHeight / rows : cssHeight;
        const playerPosition = {
          x: player.__position.x,
          y: player.__position.y,
          z: player.__position.z,
        };
        const playerProjected = renderer.getStaticScreenPosition(playerPosition);
        const playerMoving = typeof player?.isMoving === "function" ? Boolean(player.isMoving()) : false;
        const keepAnimatingWhileVisible = playerMoving;

        if (!cssWidth || !cssHeight) {
          root.dataset.visibleWaypoints = "0";
          root.dataset.visibleTileRules = "0";
          root.dataset.routeSize = String(state.payload.waypoints.length);
          root.dataset.activeIndex = String(state.payload.routeIndex);
          root.dataset.focusIndex = state.payload.focusIndex == null ? "" : String(state.payload.focusIndex);
          return {
            ok: true,
            visibleWaypoints: 0,
            visibleTileRules: 0,
            activeIndex: state.payload.routeIndex,
            columns,
            rows,
            needsNextFrame: keepAnimatingWhileVisible,
          };
        }

        const maxProjectedDx = columns + ${WAYPOINT_OVERLAY_PROJECTION_MARGIN_TILES};
        const maxProjectedDy = rows + ${WAYPOINT_OVERLAY_PROJECTION_MARGIN_TILES};
        const resolvedFocusIndex = state.payload.focusIndex != null
          && !state.payload.suppressRouteHighlights
          && state.payload.focusIndex >= 0
          && state.payload.focusIndex < state.payload.waypoints.length
          ? state.payload.focusIndex
          : null;
        const toCenterPoint = (projected) => ({
          x: projected.x * tileWidth + tileWidth / 2,
          y: projected.y * tileHeight + tileHeight / 2,
        });
        const isProjectedVisible = (projected) => Boolean(
          projected
          && projected.x >= -1 && projected.x <= columns
          && projected.y >= -1 && projected.y <= rows
        );
        const hashTilePosition = (position) => {
          const x = Math.trunc(Number(position?.x) || 0) >>> 0;
          const y = Math.trunc(Number(position?.y) || 0) >>> 0;
          const z = Math.trunc(Number(position?.z) || 0) >>> 0;
          return (((x * 73856093) ^ (y * 19349663) ^ (z * 83492791)) >>> 0);
        };

        const occupiedTileKeys = new Set();
        const occupiedMasks = [];
        let movingCreatureCount = 0;
        let occupiedTileCount = 0;
        let occupiedTileHash = 0;
        let occupiedTileXor = 0;
        const registerCreatureMask = (position, moving = false) => {
          if (!position || Number(position.z) !== Number(playerPosition.z)) return;
          const projected = renderer.getStaticScreenPosition(position);
          if (!isProjectedVisible(projected)) return;
          const tileKey = String(position.x) + "," + String(position.y) + "," + String(position.z);
          if (occupiedTileKeys.has(tileKey)) {
            if (moving) movingCreatureCount += 1;
            return;
          }
          occupiedTileKeys.add(tileKey);
          occupiedTileCount += 1;
          const tileHash = hashTilePosition(position);
          occupiedTileHash = (occupiedTileHash + tileHash) >>> 0;
          occupiedTileXor = (occupiedTileXor ^ tileHash) >>> 0;
          occupiedMasks.push(toCenterPoint(projected));
          if (moving) movingCreatureCount += 1;
        };

        registerCreatureMask(playerPosition, playerMoving);
        collectValues(world?.activeCreatures).forEach((creature) => {
          const position = readPosition(creature);
          const moving = typeof creature?.isMoving === "function" ? Boolean(creature.isMoving()) : false;
          registerCreatureMask(position, moving);
        });

        const frameSignature = [
          state.payloadRevision,
          Math.round(viewportRect.left * 10),
          Math.round(viewportRect.top * 10),
          Math.round(cssWidth * 10),
          Math.round(cssHeight * 10),
          screen.width || 0,
          screen.height || 0,
          dpr,
          playerPosition.x,
          playerPosition.y,
          playerPosition.z,
          playerProjected ? String(playerProjected.x) + "," + String(playerProjected.y) : "",
          resolvedFocusIndex ?? "",
          state.payload.routeIndex,
          occupiedTileCount,
          occupiedTileHash,
          occupiedTileXor,
          movingCreatureCount,
        ].join("|");
        const keepAnimating = keepAnimatingWhileVisible || movingCreatureCount > 0;
        if (!state.needsRedraw && !keepAnimating && frameSignature === state.lastFrameSignature) {
          return {
            ...(state.lastStats || {}),
            ok: true,
            skipped: true,
            needsNextFrame: false,
          };
        }

        state.needsRedraw = false;
        state.lastFrameSignature = frameSignature;

        ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
        ctx.clearRect(0, 0, cssWidth, cssHeight);
        ctx.imageSmoothingEnabled = false;
        ctx.lineCap = "round";
        ctx.lineJoin = "round";
        ctx.textAlign = "center";
        ctx.textBaseline = "middle";

        let visibleTileRules = 0;
        state.payload.tileRules.forEach((rule) => {
          if (!rule || Number(rule.z) !== Number(playerPosition.z)) return;

          const projected = renderer.getStaticScreenPosition({
            x: rule.x,
            y: rule.y,
            z: rule.z,
          });
          if (!projected || projected.x + Math.max(1, Number(rule.width) || 1) < -1 || projected.x > columns || projected.y + Math.max(1, Number(rule.height) || 1) < -1 || projected.y > rows) {
            return;
          }

          visibleTileRules += 1;
          const areaWidth = tileWidth * Math.max(1, Number(rule.width) || 1);
          const areaHeight = tileHeight * Math.max(1, Number(rule.height) || 1);
          const left = projected.x * tileWidth;
          const top = projected.y * tileHeight;
          const ruleStyle = getRuleStyle(rule.policy);

          ctx.save();
          ctx.lineWidth = 1;
          ctx.fillStyle = ruleStyle.fill;
          ctx.fillRect(
            Math.round(left) + 1,
            Math.round(top) + 1,
            Math.max(1, Math.round(areaWidth) - 2),
            Math.max(1, Math.round(areaHeight) - 2),
          );
          ctx.strokeStyle = ruleStyle.stroke;
          ctx.setLineDash(rule.shape === "rect" ? [4, 3] : [3, 3]);
          ctx.strokeRect(
            Math.round(left) + 0.5,
            Math.round(top) + 0.5,
            Math.max(1, Math.round(areaWidth) - 1),
            Math.max(1, Math.round(areaHeight) - 1),
          );
          ctx.restore();
        });

        const visibleEntries = [];
        const stackedByTile = new Map();
        const previewRankByIndex = new Map();
        if (!state.payload.suppressRouteHighlights) {
          const previewCount = Math.min(5, state.payload.waypoints.length);
          for (let step = 0; step < previewCount; step += 1) {
            let previewIndex = state.payload.routeIndex + step;
            if (previewIndex >= state.payload.waypoints.length) {
              if (!state.payload.autowalkLoop || !state.payload.waypoints.length) break;
              previewIndex %= state.payload.waypoints.length;
            }
            if (!previewRankByIndex.has(previewIndex)) {
              previewRankByIndex.set(previewIndex, step);
            }
          }
        }

        state.payload.waypoints.forEach((waypoint, index) => {
          if (!waypoint || waypoint.z !== playerPosition.z) return;
          const dx = waypoint.x - playerPosition.x;
          const dy = waypoint.y - playerPosition.y;
          if (Math.abs(dx) > maxProjectedDx || Math.abs(dy) > maxProjectedDy) return;

          const projected = renderer.getStaticScreenPosition(waypoint);
          if (!isProjectedVisible(projected)) return;

          const entry = {
            index,
            waypoint,
            point: toCenterPoint(projected),
            tileKey: waypoint.x + "," + waypoint.y + "," + waypoint.z,
            isRouteIndex: !state.payload.suppressRouteHighlights && index === state.payload.routeIndex,
            isFocusIndex: !state.payload.suppressRouteHighlights && index === resolvedFocusIndex,
          };

          visibleEntries.push(entry);
          const group = stackedByTile.get(entry.tileKey) || [];
          group.push(entry);
          stackedByTile.set(entry.tileKey, group);
        });

        const renderEntries = [];
        for (const group of stackedByTile.values()) {
          group.sort((left, right) => left.index - right.index);
          const primary = group.find((entry) => entry.isFocusIndex)
            || group.find((entry) => entry.isRouteIndex)
            || group[group.length - 1];
          const stepTexts = group.map((entry) => String(entry.waypoint.order));
          renderEntries.push({
            ...primary,
            isRouteIndex: group.some((entry) => entry.isRouteIndex),
            isFocusIndex: group.some((entry) => entry.isFocusIndex),
            isOccupied: occupiedTileKeys.has(primary.tileKey),
            routePreviewRank: group.reduce((best, entry) => {
              const rank = previewRankByIndex.has(entry.index) ? previewRankByIndex.get(entry.index) : null;
              if (rank == null) return best;
              if (best == null) return rank;
              return Math.min(best, rank);
            }, null),
            stackCount: group.length,
            stepTexts,
            displayLabel: String(primary.waypoint.tinyLabel || "").trim() || "WP",
          });
        }

        const orderedRenderEntries = renderEntries
          .slice()
          .sort((left, right) => Number(left.isRouteIndex || left.isFocusIndex) - Number(right.isRouteIndex || right.isFocusIndex));

        const drawWaypointTile = (entry) => {
          const emphasized = entry.isRouteIndex || entry.isFocusIndex;
          const stacked = entry.stackCount > 1;
          const style = getTypeStyle(entry.waypoint.type || "${DEFAULT_WAYPOINT_TYPE}", emphasized);
          const routePreviewColor = getRoutePreviewColor(entry.routePreviewRank);
          const markerScale = Math.min(0.95, 0.92 + (emphasized ? 0.015 : 0));
          const markerWidth = Math.max(10, Math.min(tileWidth, tileWidth * markerScale));
          const markerHeight = Math.max(10, Math.min(tileHeight, tileHeight * markerScale));
          const centerX = entry.point.x;
          const centerY = entry.point.y;
          const left = centerX - markerWidth / 2;
          const top = centerY - markerHeight / 2;
          const roundedLeft = Math.round(left) + 0.5;
          const roundedTop = Math.round(top) + 0.5;
          const roundedWidth = Math.max(4, Math.round(markerWidth) - 1);
          const roundedHeight = Math.max(4, Math.round(markerHeight) - 1);
          const radius = Math.max(4, Math.min(roundedWidth, roundedHeight) * 0.22);
          const segmentLength = Math.max(4, Math.min(roundedWidth, roundedHeight) * 0.18);
          const echoCount = Math.min(entry.stackCount - 1, 3);
          const frameStroke = stacked ? boostColorAlpha(style.stroke, emphasized ? 0.04 : 0.16) : style.stroke;
          const frameEdge = stacked ? boostColorAlpha(style.edge, emphasized ? 0.03 : 0.08) : style.edge;
          const frameFill = stacked ? multiplyColorAlpha(style.fill, 0.55) : style.fill;
          const baseLineWidth = (emphasized ? 1.46 : 1.06) + (stacked ? 0.32 : 0);

          ctx.save();
          for (let depth = echoCount; depth >= 1; depth -= 1) {
            const offset = depth * Math.max(1.5, Math.min(tileWidth, tileHeight) * 0.055);
            const echoLeft = roundedLeft - offset;
            const echoTop = roundedTop - offset * 0.6;
            ctx.globalAlpha = Math.max(0.12, 0.22 - depth * 0.03);
            ctx.strokeStyle = frameStroke;
            ctx.lineWidth = 1.05;
            if (entry.isOccupied) {
              traceSegmentedFrame(ctx, echoLeft, echoTop, roundedWidth, roundedHeight, radius, segmentLength);
            } else {
              traceRoundedRect(ctx, echoLeft, echoTop, roundedWidth, roundedHeight, radius);
            }
            ctx.stroke();
          }
          ctx.globalAlpha = 1;

          ctx.strokeStyle = frameStroke;
          ctx.lineWidth = baseLineWidth + (entry.isRouteIndex && entry.isFocusIndex ? 0.16 : 0);
          if (entry.isOccupied) {
            traceSegmentedFrame(ctx, roundedLeft, roundedTop, roundedWidth, roundedHeight, radius, segmentLength);
            ctx.stroke();
            ctx.strokeStyle = frameEdge;
            ctx.lineWidth = 1;
            traceSegmentedFrame(ctx, roundedLeft, roundedTop, roundedWidth, roundedHeight, radius, Math.max(3, segmentLength - 1.5));
            ctx.stroke();
          } else {
            ctx.fillStyle = frameFill;
            traceRoundedRect(ctx, roundedLeft, roundedTop, roundedWidth, roundedHeight, radius);
            ctx.fill();
            ctx.strokeStyle = frameStroke;
            traceRoundedRect(ctx, roundedLeft, roundedTop, roundedWidth, roundedHeight, radius);
            ctx.stroke();
            ctx.strokeStyle = frameEdge;
            ctx.lineWidth = 1;
            ctx.beginPath();
            ctx.moveTo(roundedLeft + radius + 2, roundedTop + 1.5);
            ctx.lineTo(roundedLeft + roundedWidth - radius - 2, roundedTop + 1.5);
            ctx.stroke();
          }

          if (routePreviewColor) {
            ctx.strokeStyle = routePreviewColor;
            ctx.lineWidth = Math.min(1.86, baseLineWidth + 0.16);
            if (entry.isOccupied) {
              traceSegmentedFrame(ctx, roundedLeft, roundedTop, roundedWidth, roundedHeight, radius, segmentLength + 1.5);
              ctx.stroke();
            } else {
              traceRoundedRect(ctx, roundedLeft, roundedTop, roundedWidth, roundedHeight, radius);
              ctx.stroke();
            }
          }

          ctx.restore();
          entry.drawBox = {
            left: roundedLeft,
            top: roundedTop,
            width: roundedWidth,
            height: roundedHeight,
            centerX,
            centerY,
          };
        };

        const drawWaypointChrome = (entry) => {
          const box = entry.drawBox;
          if (!box) return;
          const emphasized = entry.isRouteIndex || entry.isFocusIndex;

          ctx.save();

          if (entry.isOccupied) {
            ctx.restore();
            return;
          }

          const stepTexts = Array.isArray(entry.stepTexts) && entry.stepTexts.length
            ? entry.stepTexts.map((value) => String(value).trim()).filter(Boolean)
            : [String(entry.waypoint.order)];
          const stackedNumbers = stepTexts.length > 1;
          const longestStepLength = stepTexts.reduce((best, value) => Math.max(best, String(value).length), 0);
          const labelText = entry.routePreviewRank != null
            ? clipText(entry.displayLabel, stackedNumbers ? 7 : 10)
            : "";
          const hasLabel = Boolean(labelText);
          const labelFontSize = hasLabel
            ? Math.max(7, Math.min(Math.min(box.width, box.height) * 0.155, emphasized ? 8.5 : 7.75))
            : 0;
          const baseStepFontSize = Math.max(9, Math.min(Math.min(box.width, box.height) * (hasLabel ? 0.305 : 0.32), emphasized ? 13 : 12));
          const stackedFontScale = stackedNumbers
            ? (longestStepLength >= 3
                ? (stepTexts.length >= 4 ? 0.44 : stepTexts.length >= 3 ? 0.47 : 0.52)
                : (stepTexts.length >= 4 ? 0.5 : stepTexts.length >= 3 ? 0.56 : 0.64))
            : 1;
          const minimumStepFontSize = stackedNumbers
            ? (longestStepLength >= 3 ? 4.9 : 5.6)
            : 8.5;
          let stepFontSize = stackedNumbers
            ? Math.max(minimumStepFontSize, Math.min(baseStepFontSize * stackedFontScale, emphasized ? 8.2 : 7.45))
            : baseStepFontSize;
          const contentGap = hasLabel ? Math.max(1.5, Math.min(3, box.height * 0.05)) : 0;
          const stepAreaTop = box.top + 2;
          const stepAreaHeight = hasLabel
            ? Math.max(8, box.height - labelFontSize - contentGap - 4)
            : Math.max(10, box.height - 4);
          const stepCenterY = stepAreaTop + stepAreaHeight / 2;
          const labelCenterY = hasLabel
            ? stepAreaTop + stepAreaHeight + contentGap + labelFontSize / 2
            : box.centerY;
          const tintSequence = getStepTintSequence(stepTexts.length);
          const buildStepBadgeItems = (values, fontSize) => {
            return values.map((text, index) => {
              const textWidth = Math.max(fontSize * 0.68, ctx.measureText(text).width);
              const paddingX = stackedNumbers
                ? Math.max(1.05, fontSize * (longestStepLength >= 3 ? 0.22 : 0.3))
                : Math.max(1.4, fontSize * 0.42);
              const paddingY = Math.max(0.7, fontSize * (stackedNumbers ? 0.18 : 0.22));
              const badgeWidth = Math.max(fontSize * 1.55, textWidth + paddingX * 2);
              const badgeHeight = Math.max(fontSize + paddingY * 2, fontSize * (stackedNumbers ? 1.2 : 1.16));
              const tint = STEP_TINT_PALETTE[tintSequence[index]] || STEP_TINT_PALETTE.white;
              return {
                text,
                tint,
                width: badgeWidth,
                height: badgeHeight,
              };
            });
          };
          const buildStepBadgeLayout = (items, centerX, centerY, width, height) => {
            const count = Math.max(1, items.length);
            const maxBadgeWidth = items.reduce((best, item) => Math.max(best, item.width), 0);
            const maxBadgeHeight = items.reduce((best, item) => Math.max(best, item.height), 0);
            const horizontalGap = Math.max(1.3, Math.min(width * 0.12, maxBadgeWidth * 0.18 + stepFontSize * 0.12));
            const verticalGap = Math.max(1.2, Math.min(height * 0.12, maxBadgeHeight * 0.24 + stepFontSize * 0.1));
            const placeRow = (rowItems, y) => {
              const totalWidth = rowItems.reduce((sum, item) => sum + item.width, 0)
                + Math.max(0, rowItems.length - 1) * horizontalGap;
              let cursorLeft = centerX - totalWidth / 2;
              return rowItems.map((item) => {
                const layoutItem = {
                  text: item.text,
                  tint: item.tint,
                  x: cursorLeft + item.width / 2,
                  y,
                  left: cursorLeft,
                  top: y - item.height / 2,
                  width: item.width,
                  height: item.height,
                };
                cursorLeft += item.width + horizontalGap;
                return layoutItem;
              });
            };
            if (count === 1) {
              return placeRow(items, centerY);
            }
            if (count === 2) {
              return placeRow(items, centerY);
            }
            if (count === 3) {
              const rowGap = maxBadgeHeight + verticalGap;
              return [
                ...placeRow(items.slice(0, 2), centerY - rowGap / 2),
                ...placeRow(items.slice(2), centerY + rowGap / 2),
              ];
            }
            if (count === 4) {
              const rowGap = maxBadgeHeight + verticalGap;
              return [
                ...placeRow(items.slice(0, 2), centerY - rowGap / 2),
                ...placeRow(items.slice(2, 4), centerY + rowGap / 2),
              ];
            }
            const columnCount = 2;
            const rowCount = Math.ceil(count / columnCount);
            const rowGap = maxBadgeHeight + verticalGap;
            const firstRowY = centerY - ((rowCount - 1) * rowGap) / 2;
            const layout = [];
            for (let row = 0; row < rowCount; row += 1) {
              const rowStart = row * columnCount;
              const rowItems = items.slice(rowStart, rowStart + columnCount);
              layout.push(...placeRow(rowItems, firstRowY + row * rowGap));
            }
            return layout;
          };
          const getLayoutBounds = (items) => {
            if (!items.length) {
              return { width: 0, height: 0 };
            }
            const left = Math.min(...items.map((item) => item.left));
            const top = Math.min(...items.map((item) => item.top));
            const right = Math.max(...items.map((item) => item.left + item.width));
            const bottom = Math.max(...items.map((item) => item.top + item.height));
            return {
              width: right - left,
              height: bottom - top,
            };
          };
          let stepLayout = [];
          for (let attempt = 0; attempt < 4; attempt += 1) {
            ctx.font = "800 " + String(stepFontSize) + "px system-ui, sans-serif";
            const stepItems = buildStepBadgeItems(stepTexts, stepFontSize);
            stepLayout = buildStepBadgeLayout(
              stepItems,
              box.centerX,
              stepCenterY,
              Math.max(6, box.width - 4),
              stepAreaHeight,
            );
            const layoutBounds = getLayoutBounds(stepLayout);
            if (layoutBounds.width <= Math.max(6, box.width - 4) && layoutBounds.height <= stepAreaHeight) {
              break;
            }
            const nextFontSize = Math.max(minimumStepFontSize, stepFontSize * 0.9);
            if (nextFontSize === stepFontSize) {
              break;
            }
            stepFontSize = nextFontSize;
          }
          ctx.font = "800 " + String(stepFontSize) + "px system-ui, sans-serif";
          stepLayout.forEach(({ left, top, width, height, tint }) => {
            ctx.fillStyle = tint.badgeFill;
            ctx.strokeStyle = tint.badgeStroke;
            ctx.lineWidth = Math.max(0.8, stepFontSize * 0.09);
            traceRoundedRect(
              ctx,
              left,
              top,
              width,
              height,
              Math.max(2.6, Math.min(width, height) * 0.36),
            );
            ctx.fill();
            ctx.stroke();
          });
          ctx.font = "800 " + String(stepFontSize) + "px system-ui, sans-serif";
          ctx.lineWidth = Math.max(1, stepFontSize * 0.1);
          ctx.strokeStyle = "rgba(0,0,0,0.42)";
          stepLayout.forEach(({ text, x, y }) => {
            ctx.strokeText(text, x, y);
          });
          stepLayout.forEach(({ text, x, y, tint }) => {
            ctx.fillStyle = tint.text;
            ctx.fillText(text, x, y);
          });

          if (hasLabel) {
            ctx.save();
            ctx.beginPath();
            traceRoundedRect(ctx, box.left + 2, box.top + 2, Math.max(4, box.width - 4), Math.max(4, box.height - 4), Math.max(3, Math.min(box.width, box.height) * 0.18));
            ctx.clip();
            ctx.font = "600 " + String(labelFontSize) + "px system-ui, sans-serif";
            ctx.strokeStyle = "rgba(0,0,0,0.3)";
            ctx.lineWidth = 1;
            ctx.textAlign = "center";
            ctx.strokeText(labelText, box.centerX, labelCenterY);
            ctx.fillStyle = "rgba(255,255,255,0.9)";
            ctx.fillText(labelText, box.centerX, labelCenterY);
            ctx.restore();
            ctx.textAlign = "center";
          }

          ctx.restore();
        };

        orderedRenderEntries.forEach(drawWaypointTile);

        if (occupiedMasks.length) {
          ctx.save();
          ctx.globalCompositeOperation = "destination-out";
          ctx.fillStyle = "rgba(0,0,0,1)";
          occupiedMasks.forEach((mask) => {
            ctx.beginPath();
            ctx.ellipse(
              mask.x,
              mask.y + tileHeight * 0.06,
              Math.max(4, tileWidth * 0.34),
              Math.max(4, tileHeight * 0.28),
              0,
              0,
              Math.PI * 2,
            );
            ctx.fill();
          });
          ctx.restore();
        }

        orderedRenderEntries.forEach(drawWaypointChrome);

        const routeTelemetry = state.payload.routeTelemetry || {};
        const lapCount = Math.max(0, Math.trunc(Number(routeTelemetry.lapCount) || 0));
        const killCount = Math.max(0, Math.trunc(Number(routeTelemetry.killCount) || 0));
        const goldValue = Math.max(0, Math.trunc(Number(routeTelemetry.lootGoldValue) || 0));
        const counterStatusLine = formatOverlayCounterLine(
          routeTelemetry,
          state.payload.routeIndex,
          state.payload.waypoints.length,
        );
        const counterLootLine = formatOverlayLootLine(routeTelemetry);
        const counterLootText = counterLootLine.replace(/^LOOT\\s+/i, "") || "none";
        const counterStats = [
          { label: "LAPS", value: String(lapCount), fill: "rgba(127,236,182,0.15)", stroke: "rgba(185,255,218,0.26)", text: "rgba(225,255,239,0.98)" },
          { label: "KILLS", value: String(killCount), fill: "rgba(255,132,116,0.15)", stroke: "rgba(255,210,200,0.25)", text: "rgba(255,232,224,0.98)" },
          { label: "GOLD", value: formatOverlayCompactNumber(goldValue), fill: "rgba(251,191,36,0.15)", stroke: "rgba(255,231,154,0.28)", text: "rgba(255,247,214,0.98)" },
        ];
        const counterAlert = routeTelemetry.stuck === true;
        ctx.save();
        ctx.font = "700 10px system-ui, sans-serif";
        const counterLootWidth = ctx.measureText(counterLootLine).width;
        const counterStatusWidth = ctx.measureText(counterStatusLine).width;
        const counterPaddingX = 9;
        const counterWidth = Math.min(
          Math.max(174, Math.ceil(Math.max(counterLootWidth + 24, counterStatusWidth + 108))),
          Math.max(128, cssWidth - 12),
        );
        const counterHeight = 76;
        const counterLeft = Math.max(6, cssWidth - counterWidth - 6);
        const counterTop = 6;
        const fitText = (value, maxWidth) => {
          const text = String(value || "");
          if (ctx.measureText(text).width <= maxWidth) return text;
          let clipped = text;
          while (clipped.length > 0 && ctx.measureText(clipped + "...").width > maxWidth) {
            clipped = clipped.slice(0, -1);
          }
          return clipped ? clipped + "..." : "";
        };
        const panelGradient = ctx.createLinearGradient(0, counterTop, 0, counterTop + counterHeight);
        if (counterAlert) {
          panelGradient.addColorStop(0, "rgba(70,18,18,0.86)");
          panelGradient.addColorStop(1, "rgba(24,8,10,0.78)");
        } else {
          panelGradient.addColorStop(0, "rgba(12,31,27,0.84)");
          panelGradient.addColorStop(1, "rgba(6,12,17,0.76)");
        }
        ctx.shadowColor = "rgba(0,0,0,0.34)";
        ctx.shadowBlur = 14;
        ctx.shadowOffsetY = 5;
        ctx.fillStyle = panelGradient;
        ctx.strokeStyle = counterAlert
          ? "rgba(255,130,130,0.86)"
          : "rgba(133,244,197,0.66)";
        ctx.lineWidth = 1.25;
        traceRoundedRect(ctx, counterLeft, counterTop, counterWidth, counterHeight, 10);
        ctx.fill();
        ctx.stroke();
        ctx.shadowColor = "transparent";
        ctx.globalAlpha = 0.92;
        ctx.strokeStyle = counterAlert
          ? "rgba(255,196,196,0.18)"
          : "rgba(255,255,255,0.13)";
        traceRoundedRect(ctx, counterLeft + 2, counterTop + 2, counterWidth - 4, counterHeight - 4, 8);
        ctx.stroke();
        ctx.globalAlpha = 1;
        ctx.textAlign = "left";
        ctx.textBaseline = "middle";
        ctx.font = "800 8px system-ui, sans-serif";
        ctx.fillStyle = counterAlert
          ? "rgba(255,196,196,0.98)"
          : "rgba(177,255,223,0.98)";
        ctx.fillText("ROUTE", counterLeft + counterPaddingX, counterTop + 12);
        const statusPillWidth = Math.min(counterWidth - 72, Math.max(42, Math.ceil(counterStatusWidth) + 14));
        const statusPillLeft = counterLeft + counterWidth - counterPaddingX - statusPillWidth;
        traceRoundedRect(ctx, statusPillLeft, counterTop + 5, statusPillWidth, 15, 7);
        ctx.fillStyle = counterAlert
          ? "rgba(255,132,132,0.18)"
          : "rgba(255,255,255,0.10)";
        ctx.fill();
        ctx.strokeStyle = counterAlert
          ? "rgba(255,190,190,0.24)"
          : "rgba(255,255,255,0.16)";
        ctx.stroke();
        ctx.font = "800 8px system-ui, sans-serif";
        ctx.textAlign = "center";
        ctx.fillStyle = counterAlert
          ? "rgba(255,230,230,0.98)"
          : "rgba(255,255,255,0.96)";
        ctx.fillText(fitText(counterStatusLine, statusPillWidth - 10), statusPillLeft + statusPillWidth / 2, counterTop + 12.5);
        const statsTop = counterTop + 25;
        const statsGap = 4;
        const statsWidth = counterWidth - counterPaddingX * 2;
        const statWidth = Math.max(30, (statsWidth - statsGap * 2) / 3);
        for (let statIndex = 0; statIndex < counterStats.length; statIndex += 1) {
          const stat = counterStats[statIndex];
          const statLeft = counterLeft + counterPaddingX + statIndex * (statWidth + statsGap);
          traceRoundedRect(ctx, statLeft, statsTop, statWidth, 27, 7);
          ctx.fillStyle = stat.fill;
          ctx.fill();
          ctx.strokeStyle = stat.stroke;
          ctx.lineWidth = 1;
          ctx.stroke();
          ctx.textAlign = "center";
          ctx.font = "800 12px system-ui, sans-serif";
          ctx.fillStyle = stat.text;
          ctx.fillText(fitText(stat.value, statWidth - 8), statLeft + statWidth / 2, statsTop + 10);
          ctx.font = "700 6.5px system-ui, sans-serif";
          ctx.fillStyle = "rgba(234,242,248,0.68)";
          ctx.fillText(stat.label, statLeft + statWidth / 2, statsTop + 21);
        }
        const lootTop = counterTop + counterHeight - 18;
        const lootLeft = counterLeft + counterPaddingX;
        const lootWidth = counterWidth - counterPaddingX * 2;
        traceRoundedRect(ctx, lootLeft, lootTop, lootWidth, 13, 6);
        ctx.fillStyle = counterAlert
          ? "rgba(255,255,255,0.08)"
          : "rgba(255,255,255,0.09)";
        ctx.fill();
        ctx.textAlign = "left";
        ctx.font = "800 6.5px system-ui, sans-serif";
        ctx.fillStyle = counterAlert
          ? "rgba(255,196,196,0.9)"
          : "rgba(251,191,36,0.92)";
        ctx.fillText("LOOT", lootLeft + 7, lootTop + 7);
        ctx.font = "700 8px system-ui, sans-serif";
        ctx.fillStyle = counterAlert
          ? "rgba(255,238,228,0.96)"
          : "rgba(245,250,248,0.96)";
        ctx.fillText(fitText(counterLootText, lootWidth - 43), lootLeft + 38, lootTop + 7);
        ctx.restore();

        root.dataset.visibleWaypoints = String(visibleEntries.length);
        root.dataset.visibleTileRules = String(visibleTileRules);
        root.dataset.routeSize = String(state.payload.waypoints.length);
        root.dataset.activeIndex = String(state.payload.routeIndex);
        root.dataset.focusIndex = resolvedFocusIndex == null ? "" : String(resolvedFocusIndex);

        return {
          ok: true,
          visibleWaypoints: visibleEntries.length,
          visibleTileRules,
          activeIndex: state.payload.routeIndex,
          columns,
          rows,
          needsNextFrame: keepAnimating,
        };
      };
    }

    if (!state.startLoop) {
      state.startLoop = () => {
        if (state.running) return;
        state.running = true;
        const scheduleNext = () => {
          if (!root.isConnected) {
            state.running = false;
            state.frame = null;
            return;
          }

          state.lastStats = state.draw();
          if (state.lastStats?.needsNextFrame) {
            state.frame = window.requestAnimationFrame(scheduleNext);
            return;
          }

          state.running = false;
          state.frame = null;
        };

        scheduleNext();
      };
    }

    if (!state.bindObservers) {
      state.bindObservers = (wrapper, screen) => {
        if (!state.resizeObserver && typeof ResizeObserver === "function") {
          state.resizeObserver = new ResizeObserver(() => {
            state.requestRedraw();
          });
        }

        if (state.resizeObserver) {
          if (state.observedWrapper && state.observedWrapper !== wrapper) {
            try {
              state.resizeObserver.unobserve(state.observedWrapper);
            } catch {}
          }
          if (state.observedScreen && state.observedScreen !== screen && state.observedScreen !== state.observedWrapper) {
            try {
              state.resizeObserver.unobserve(state.observedScreen);
            } catch {}
          }
          if (wrapper && state.observedWrapper !== wrapper) {
            state.resizeObserver.observe(wrapper);
            state.observedWrapper = wrapper;
          }
          if (screen && screen !== wrapper && state.observedScreen !== screen) {
            state.resizeObserver.observe(screen);
            state.observedScreen = screen;
          }
        }

        if (!state.removeResizeListener) {
          const onResize = () => state.requestRedraw();
          window.addEventListener("resize", onResize, { passive: true });
          state.removeResizeListener = () => window.removeEventListener("resize", onResize);
        }

        if (window.visualViewport && !state.removeViewportResizeListener) {
          const onViewportResize = () => state.requestRedraw();
          const onViewportScroll = () => state.requestRedraw();
          window.visualViewport.addEventListener("resize", onViewportResize, { passive: true });
          window.visualViewport.addEventListener("scroll", onViewportScroll, { passive: true });
          state.removeViewportResizeListener = () => window.visualViewport?.removeEventListener?.("resize", onViewportResize);
          state.removeViewportScrollListener = () => window.visualViewport?.removeEventListener?.("scroll", onViewportScroll);
        }
      };
    }

    state.bindObservers(initialSurface.wrapper, initialSurface.screen);

    state.lastStats = state.draw();
    if (state.lastStats?.needsNextFrame) {
      state.startLoop();
    }
    return state.lastStats;
  })()`;
}

export function formatTarget(target) {
  if (!target) return "none";
  const pos = target.position ? `${target.position.x},${target.position.y},${target.position.z}` : "?, ?, ?";
  return `${target.name}#${target.id} @ ${pos}`;
}

function getCombatModeDescriptor(kind, value = null) {
  const rawCandidate = value?.rawValue ?? value?.value ?? value;
  const numericValue = typeof rawCandidate === "boolean"
    ? null
    : (
      typeof rawCandidate === "string" && !rawCandidate.trim()
        ? null
        : Number(rawCandidate)
    );
  if (Number.isInteger(numericValue)) {
    if (kind === "fight" && FIGHT_MODE_DESCRIPTOR_BY_RAW_VALUE[numericValue]) {
      return {
        ...FIGHT_MODE_DESCRIPTOR_BY_RAW_VALUE[numericValue],
        rawValue: numericValue,
      };
    }
    if (kind === "chase" && CHASE_MODE_DESCRIPTOR_BY_RAW_VALUE[numericValue]) {
      return {
        ...CHASE_MODE_DESCRIPTOR_BY_RAW_VALUE[numericValue],
        rawValue: numericValue,
      };
    }
  }

  const text = String(
    value?.key
    || value?.label
    || value?.name
    || value?.title
    || rawCandidate
    || "",
  ).trim().toLowerCase();
  if (!text) {
    return null;
  }

  if (kind === "fight") {
    if (/(offensive|attack|aggressive|full attack)/.test(text)) {
      return { ...FIGHT_MODE_DESCRIPTOR_BY_RAW_VALUE[0], rawValue: 0 };
    }
    if (/balanced?/.test(text)) {
      return { ...FIGHT_MODE_DESCRIPTOR_BY_RAW_VALUE[1], rawValue: 1 };
    }
    if (/(defensive|defence|defense)/.test(text)) {
      return { ...FIGHT_MODE_DESCRIPTOR_BY_RAW_VALUE[2], rawValue: 2 };
    }
  }

  if (kind === "chase") {
    if (/(stand|hold|don.?t chase|do not chase)/.test(text)) {
      return { ...CHASE_MODE_DESCRIPTOR_BY_RAW_VALUE[0], rawValue: 0 };
    }
    if (/aggressive/.test(text)) {
      return { ...CHASE_MODE_DESCRIPTOR_BY_RAW_VALUE[2], rawValue: 2 };
    }
    if (/(chase|follow)/.test(text)) {
      return { ...CHASE_MODE_DESCRIPTOR_BY_RAW_VALUE[1], rawValue: 1 };
    }
  }

  return null;
}

function createCombatModeState(kind, value = null) {
  const descriptor = getCombatModeDescriptor(kind, value);
  if (!descriptor) {
    return null;
  }

  return {
    key: descriptor.key,
    label: descriptor.label,
    rawValue: String(descriptor.rawValue),
  };
}

