    this.reconnectShutdownTelemetryPrimed = false;
    this.lastFailedValueSlotRepairSignature = "";
    this.lastFailedValueSlotRepairAt = 0;
    this.lastFailedUrgentConvertSignature = "";
    this.lastFailedUrgentConvertAt = 0;
    this.lastFailedUrgentConvertBackoffMs = 0;
    this.activeBankingConversation = null;
