  getWaypointNpcName(waypoint = {}, fallbackNames = []) {
    return normalizeTextList([
      waypoint?.npcName,
      ...normalizeTextList(fallbackNames),
    ])[0] || "";
  }

  getWaypointProgressionAction(waypoint = {}) {
    const normalized = String(
      waypoint?.progressionAction
      || waypoint?.action
      || waypoint?.objective
      || "",
    ).trim().toLowerCase();
    const aliases = {
      open: "open-dialogue",
      "open-npc-dialogue": "open-dialogue",
      close: "close-dialogue",
      "close-npc-dialogue": "close-dialogue",
      residence: "set-residence",
      blessing: "buy-blessing",
      blessings: "buy-all-missing-blessings",
      promotion: "buy-promotion",
      task: "daily-task",
    };

    if (aliases[normalized]) {
      return aliases[normalized];
    }
    if (normalized) {
      return normalized;
    }
    if (waypoint?.taskTarget || waypoint?.taskKeyword || waypoint?.rewardKeyword) {
      return "daily-task";
    }
    if (waypoint?.promotionName) {
      return "buy-promotion";
    }
    if (waypoint?.blessing) {
      return "buy-blessing";
    }
    if (waypoint?.residence) {
      return "set-residence";
    }
    if (waypoint?.city || waypoint?.destination) {
      return "travel";
    }
    return "open-dialogue";
  }

  shouldAdvanceNpcRouteResult(result = {}) {
    return result?.completed === true || (result?.ok === true && result?.waiting !== true);
  }

  advanceCompletedNpcRouteWaypoint(reason = "npc action") {
    this.markWaypointConfirmed(this.routeIndex);
    this.advanceWaypoint(reason);
  }

  async speakNpcKeyword(action = {}) {
    const keyword = String(action.keyword ?? action.words ?? action.text ?? "").trim();
    if (!keyword) {
      return { ok: false, reason: "missing npc keyword" };
    }

    return this.castWords({
      ...action,
      type: "npc-keyword",
      words: keyword,
    });
  }

